package com.kartik.aistudyassistant.data.repository

import android.app.Activity
import android.content.Context
import android.util.Log
import androidx.credentials.*
import androidx.credentials.exceptions.GetCredentialException
import com.kartik.aistudyassistant.data.model.AuthResult as AppAuthResult
import com.google.android.libraries.identity.googleid.*
import com.google.firebase.FirebaseException
import com.google.firebase.auth.*
import com.google.firebase.database.FirebaseDatabase
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext
import java.util.concurrent.TimeUnit
import java.util.UUID

class AuthManager(private val context: Context) {

    private val auth: FirebaseAuth = FirebaseAuth.getInstance()
    private val credentialManager = CredentialManager.create(context)
    private val database = FirebaseDatabase.getInstance()
    private val tag = "AuthManager"

    companion object {
        // Cache for user existence checks
        private val emailUserCache = mutableMapOf<String, CachedUserData>()
        private const val CACHE_DURATION = 5 * 60 * 1000 // 5 minutes
        private const val PHONE_LENGTH = 10
        private const val OTP_TIMEOUT_SECONDS = 60L
        private const val TEMP_PASSWORD_PREFIX = "Tmp#"

        data class CachedUserData(
            val uid: String,
            val provider: String,
            val timestamp: Long
        ) {
            fun isValid(): Boolean = System.currentTimeMillis() - timestamp < CACHE_DURATION
        }

    }

    fun checkCurrentUserVerification(callback: (AppAuthResult) -> Unit) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(AppAuthResult.Error("User not logged in"))
            return
        }

        evaluateVerificationState(currentUser, false, callback)
    }

    fun sendEmailVerificationForCurrentUser(callback: (AppAuthResult) -> Unit) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(AppAuthResult.Error("User not logged in"))
            return
        }

        currentUser.sendEmailVerification()
            .addOnSuccessListener {
                callback(AppAuthResult.Success(false))
            }
            .addOnFailureListener { e ->
                callback(AppAuthResult.Error(e.message ?: "Failed to send verification email"))
            }
    }

    fun startPendingEmailVerification(email: String, callback: (AppAuthResult) -> Unit) {
        val normalizedEmail = email.trim().lowercase()
        if (normalizedEmail.isBlank()) {
            callback(AppAuthResult.Error("Email is required"))
            return
        }

        CoroutineScope(Dispatchers.IO).launch {
            try {
                val existingUserData = checkEmailExists(normalizedEmail)
                if (existingUserData != null) {
                    withContext(Dispatchers.Main) {
                        callback(
                            AppAuthResult.Error(
                                "An account already exists with this email using ${existingUserData.provider}."
                            )
                        )
                    }
                    return@launch
                }

                withContext(Dispatchers.Main) {
                    val currentUser = auth.currentUser
                    if (currentUser != null && currentUser.email.equals(normalizedEmail, ignoreCase = true)) {
                        sendEmailVerificationForCurrentUser(callback)
                    } else {
                        auth.signOut()
                        val tempPassword = buildTempPassword()
                        auth.createUserWithEmailAndPassword(normalizedEmail, tempPassword)
                            .addOnSuccessListener {
                                auth.currentUser?.sendEmailVerification()
                                    ?.addOnSuccessListener { callback(AppAuthResult.Success(true)) }
                                    ?.addOnFailureListener { e ->
                                        callback(
                                            AppAuthResult.Error(
                                                e.message ?: "Failed to send verification email"
                                            )
                                        )
                                    }
                            }
                            .addOnFailureListener { e ->
                                callback(AppAuthResult.Error(e.message ?: "Unable to start email verification"))
                            }
                    }
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error(e.message ?: "Unable to start email verification"))
                }
            }
        }
    }

    fun refreshEmailVerificationStatus(callback: (Boolean, String?) -> Unit) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(false, "Please verify email first")
            return
        }

        currentUser.reload()
            .addOnSuccessListener {
                callback(currentUser.isEmailVerified, null)
            }
            .addOnFailureListener { e ->
                callback(false, e.message ?: "Failed to refresh email verification")
            }
    }

    fun completeVerifiedEmailSignUp(
        phone: String,
        password: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(AppAuthResult.Error("Please verify email first"))
            return
        }

        if (!currentUser.isEmailVerified) {
            callback(AppAuthResult.Error("Email is not verified yet"))
            return
        }

        val verifiedPhone = currentUser.phoneNumber
        val resolvedPhone = if (!verifiedPhone.isNullOrBlank()) {
            toLocalPhone(verifiedPhone)
        } else {
            phone.trim()
        }

        CoroutineScope(Dispatchers.IO).launch {
            val phoneExists = checkPhoneExists(resolvedPhone, currentUser.uid)
            if (phoneExists) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error("This phone number is already registered with another account."))
                }
                return@launch
            }

            withContext(Dispatchers.Main) {
                currentUser.updatePassword(password)
                    .addOnSuccessListener {
                        val email = currentUser.email.orEmpty()
                        saveUserToDatabase(
                            uid = currentUser.uid,
                            email = email,
                            phone = resolvedPhone,
                            provider = "password",
                            isNewUser = true,
                            callback = { dbResult ->
                                when (dbResult) {
                                    is AppAuthResult.Success -> evaluateVerificationState(currentUser, true, callback)
                                    else -> callback(dbResult)
                                }
                            }
                        )
                    }
                    .addOnFailureListener { e ->
                        callback(AppAuthResult.Error(e.message ?: "Failed to finalize account setup"))
                    }
            }
        }
    }

    fun startPhoneVerification(
        activity: Activity,
        rawPhone: String,
        onCodeSent: (verificationId: String, token: PhoneAuthProvider.ForceResendingToken) -> Unit,
        onVerified: (AppAuthResult) -> Unit,
        onError: (String) -> Unit
    ) {
        val phoneE164 = normalizePhoneToE164(rawPhone)
        if (phoneE164 == null) {
            onError("Enter a valid phone number")
            return
        }

        val callbacks = buildPhoneCallbacks(phoneE164, onCodeSent, onVerified, onError)
        val options = PhoneAuthOptions.newBuilder(auth)
            .setPhoneNumber(phoneE164)
            .setTimeout(OTP_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .setActivity(activity)
            .setCallbacks(callbacks)
            .build()

        PhoneAuthProvider.verifyPhoneNumber(options)
    }

    fun resendPhoneVerification(
        activity: Activity,
        rawPhone: String,
        token: PhoneAuthProvider.ForceResendingToken,
        onCodeSent: (verificationId: String, resendToken: PhoneAuthProvider.ForceResendingToken) -> Unit,
        onVerified: (AppAuthResult) -> Unit,
        onError: (String) -> Unit
    ) {
        val phoneE164 = normalizePhoneToE164(rawPhone)
        if (phoneE164 == null) {
            onError("Enter a valid phone number")
            return
        }

        val callbacks = buildPhoneCallbacks(phoneE164, onCodeSent, onVerified, onError)
        val options = PhoneAuthOptions.newBuilder(auth)
            .setPhoneNumber(phoneE164)
            .setTimeout(OTP_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .setActivity(activity)
            .setCallbacks(callbacks)
            .setForceResendingToken(token)
            .build()

        PhoneAuthProvider.verifyPhoneNumber(options)
    }

    fun verifyPhoneCode(
        verificationId: String,
        code: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val credential = PhoneAuthProvider.getCredential(verificationId, code)
        linkPhoneCredential(credential, callback)
    }

    fun getCurrentUserStoredPhone(callback: (String?) -> Unit) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(null)
            return
        }

        database.reference.child("Users").child(currentUser.uid).child("phone")
            .get()
            .addOnSuccessListener { snapshot ->
                callback(snapshot.getValue(String::class.java))
            }
            .addOnFailureListener {
                callback(null)
            }
    }

    // Google Sign-In
    fun signInWithGoogle(callback: (AppAuthResult) -> Unit) {
        val googleIdOption = GetGoogleIdOption.Builder()
            .setFilterByAuthorizedAccounts(false)
            .setServerClientId(
                context.getString(com.kartik.aistudyassistant.R.string.default_web_client_id)
            )
            .build()

        val request = GetCredentialRequest.Builder()
            .addCredentialOption(googleIdOption)
            .build()

        CoroutineScope(Dispatchers.Main).launch {
            try {
                val result = credentialManager.getCredential(
                    request = request,
                    context = context
                )

                val credential = result.credential

                if (credential is CustomCredential &&
                    credential.type == GoogleIdTokenCredential.TYPE_GOOGLE_ID_TOKEN_CREDENTIAL
                ) {
                    val googleIdTokenCredential =
                        GoogleIdTokenCredential.createFrom(credential.data)

                    handleProviderSignIn(
                        idToken = googleIdTokenCredential.idToken,
                        provider = "google.com",
                        email = googleIdTokenCredential.id,
                        callback = callback
                    )
                } else {
                    callback(AppAuthResult.Error("Invalid credential type"))
                }
            } catch (e: GetCredentialException) {
                if (e.message?.contains("cancelled", ignoreCase = true) == true) {
                    callback(AppAuthResult.Cancelled)
                } else {
                    callback(AppAuthResult.Error(e.message))
                }
            }
        }
    }

    // GitHub Sign-In
    fun signInWithGithub(activity: Activity, callback: (AppAuthResult) -> Unit) {
        val provider = OAuthProvider.newBuilder("github.com")
            .addCustomParameter("allow_signup", "true") // Fixed: Allow signups
            .build()

        auth.startActivityForSignInWithProvider(activity, provider)
            .addOnSuccessListener { authResult ->
                val user = authResult.user
                user?.let {
                    val email = it.email ?: ""
                    // Check if user exists in database and handle accordingly
                    CoroutineScope(Dispatchers.IO).launch {
                        try {
                            val existingUserData = checkEmailExists(email)

                            withContext(Dispatchers.Main) {
                                if (existingUserData != null && existingUserData.uid != it.uid) {
                                    // Email exists with different UID - this shouldn't happen with GitHub
                                    // Handle by linking or showing error
                                    callback(AppAuthResult.Error(
                                        "This email is already registered with ${existingUserData.provider}. " +
                                                "Please sign in with ${existingUserData.provider} first."
                                    ))
                                } else {
                                    // Either new user or same user, save/update in database
                                    saveUserToDatabase(
                                        uid = it.uid,
                                        email = email,
                                        phone = "",
                                        provider = "github.com",
                                        isNewUser = authResult.additionalUserInfo?.isNewUser ?: false,
                                        callback = { dbResult ->
                                            when (dbResult) {
                                                is AppAuthResult.Success -> {
                                                    evaluateVerificationState(
                                                        it,
                                                        authResult.additionalUserInfo?.isNewUser ?: false,
                                                        callback
                                                    )
                                                }
                                                else -> callback(dbResult)
                                            }
                                        }
                                    )
                                }
                            }
                        } catch (e: Exception) {
                            withContext(Dispatchers.Main) {
                                callback(AppAuthResult.Error(e.message))
                            }
                        }
                    }
                } ?: callback(AppAuthResult.Error("Failed to get user info"))
            }
            .addOnFailureListener { e ->
                if (e.message?.contains("cancelled", ignoreCase = true) == true) {
                    callback(AppAuthResult.Cancelled)
                } else {
                    callback(AppAuthResult.Error(e.message ?: "GitHub sign-in failed"))
                }
            }
    }

    // Email/Password Sign Up
    fun signUpWithEmail(email: String, password: String, phone: String, callback: (AppAuthResult) -> Unit) {
        CoroutineScope(Dispatchers.IO).launch {
            try {
                // Check if email exists in our database first
                val existingUserData = checkEmailExists(email)
                if (existingUserData != null) {
                    withContext(Dispatchers.Main) {
                        callback(AppAuthResult.Error(
                            "An account already exists with this email using ${existingUserData.provider}."
                        ))
                    }
                    return@launch
                }

                // Check if phone exists (Problem #5 fix)
                val phoneExists = checkPhoneExists(phone)
                if (phoneExists) {
                    withContext(Dispatchers.Main) {
                        callback(AppAuthResult.Error("This phone number is already registered with another account."))
                    }
                    return@launch
                }

                // Create new account with password
                withContext(Dispatchers.Main) {
                    createEmailAccount(email, password, phone, callback)
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error(e.message))
                }
            }
        }
    }

    // Email/Password Sign In
    fun signInWithEmail(email: String, password: String, callback: (AppAuthResult) -> Unit) {
        auth.signInWithEmailAndPassword(email, password)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    val user = auth.currentUser
                    user?.let {
                        updateUserPhoneIfNeeded(it.uid, email) { updateResult ->
                            when (updateResult) {
                                is AppAuthResult.Error -> callback(updateResult)
                                else -> evaluateVerificationState(it, false, callback)
                            }
                        }
                    } ?: callback(AppAuthResult.Error("User not found"))
                } else {
                    val exception = task.exception
                    when {
                        exception is FirebaseAuthInvalidUserException -> {
                            callback(AppAuthResult.Error("No account found with this email"))
                        }
                        exception is FirebaseAuthInvalidCredentialsException -> {
                            callback(AppAuthResult.Error("Invalid password"))
                        }
                        else -> {
                            callback(AppAuthResult.Error(exception?.message ?: "Sign in failed"))
                        }
                    }
                }
            }
    }

    // Handle provider sign-in (Google)
    private fun handleProviderSignIn(
        idToken: String,
        provider: String,
        email: String,
        callback: (AppAuthResult) -> Unit
    ) {
        CoroutineScope(Dispatchers.IO).launch {
            try {
                // Check if email exists in database
                val existingUserData = checkEmailExists(email)

                withContext(Dispatchers.Main) {
                    if (existingUserData != null) {
                        // Email exists, try to sign in with credential and link
                        linkProviderToExistingAccount(
                            idToken = idToken,
                            provider = provider,
                            existingUid = existingUserData.uid,
                            existingProvider = existingUserData.provider,
                            callback = callback
                        )
                    } else {
                        // New email, create account with this provider
                        createProviderAccount(
                            idToken = idToken,
                            provider = provider,
                            email = email,
                            callback = callback
                        )
                    }
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error(e.message))
                }
            }
        }
    }

    // Link provider to existing account
    private fun linkProviderToExistingAccount(
        idToken: String,
        provider: String,
        existingUid: String,
        existingProvider: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val credential = when (provider) {
            "google.com" -> GoogleAuthProvider.getCredential(idToken, null)
            else -> null
        }

        if (credential == null) {
            callback(AppAuthResult.Error("Invalid provider"))
            return
        }

        // Try to sign in with the new credential
        auth.signInWithCredential(credential)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    // Successfully signed in with new provider
                    val user = auth.currentUser
                    if (user?.uid == existingUid) {
                        // Same account, already linked
                        updateUserData(user.uid, provider, callback)
                    } else {
                        // Different account, need to link
                        linkAccounts(user, existingUid, provider, callback)
                    }
                } else {
                    val exception = task.exception
                    when {
                        exception is FirebaseAuthUserCollisionException -> {
                            // Email already used with another provider
                            handleAccountCollision(exception, provider, callback)
                        }
                        else -> {
                            callback(AppAuthResult.Error(exception?.message ?: "Authentication failed"))
                        }
                    }
                }
            }
    }

    // Handle account collision (email exists with different provider)
    private fun handleAccountCollision(
        exception: FirebaseAuthUserCollisionException,
        newProvider: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val email = exception.email ?: ""

        CoroutineScope(Dispatchers.IO).launch {
            try {
                val existingUserData = checkEmailExists(email)

                withContext(Dispatchers.Main) {
                    if (existingUserData != null) {
                        callback(AppAuthResult.Error(
                            "This email is already registered with ${existingUserData.provider}. " +
                                    "Please sign in with ${existingUserData.provider} first, then you can link your $newProvider account."
                        ))
                    } else {
                        callback(AppAuthResult.Error("Email already in use with another provider"))
                    }
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error(e.message))
                }
            }
        }
    }

    // Link two accounts
    private fun linkAccounts(
        newUser: FirebaseUser?,
        existingUid: String,
        provider: String,
        callback: (AppAuthResult) -> Unit
    ) {
        if (newUser == null) {
            callback(AppAuthResult.Error("Failed to link accounts"))
            return
        }

        // Sign in with existing account first
        // This is complex - in a real app, you'd prompt user to sign in with original provider
        // For now, we'll delete the new account and ask user to sign in with original provider
        newUser.delete()
            .addOnCompleteListener {
                callback(AppAuthResult.Error(
                    "Please sign in with your original provider first, then link this provider."
                ))
            }
    }

    // Create account with provider (Google)
    private fun createProviderAccount(
        idToken: String,
        provider: String,
        email: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val credential = when (provider) {
            "google.com" -> GoogleAuthProvider.getCredential(idToken, null)
            else -> null
        }

        credential?.let {
            auth.signInWithCredential(it)
                .addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        val user = auth.currentUser
                        user?.let {
                            saveUserToDatabase(
                                uid = it.uid,
                                email = email,
                                phone = "",
                                provider = provider,
                                isNewUser = true,
                                callback = { dbResult ->
                                    when (dbResult) {
                                        is AppAuthResult.Success -> evaluateVerificationState(it, true, callback)
                                        else -> callback(dbResult)
                                    }
                                }
                            )
                        } ?: callback(AppAuthResult.Error("Failed to create account"))
                    } else {
                        callback(AppAuthResult.Error(task.exception?.message ?: "Authentication failed"))
                    }
                }
        }
    }

    // Create email/password account
    private fun createEmailAccount(
        email: String,
        password: String,
        phone: String,
        callback: (AppAuthResult) -> Unit
    ) {
        auth.createUserWithEmailAndPassword(email, password)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    val user = auth.currentUser
                    user?.let { firebaseUser ->
                        firebaseUser.sendEmailVerification()
                            .addOnSuccessListener {
                                saveUserToDatabase(
                                    uid = firebaseUser.uid,
                                    email = email,
                                    phone = phone,
                                    provider = "password",
                                    isNewUser = true,
                                    callback = { dbResult ->
                                        when (dbResult) {
                                            is AppAuthResult.Success -> {
                                                callback(
                                                    AppAuthResult.VerificationRequired(
                                                        emailVerified = false,
                                                        phoneVerified = false,
                                                        message = "Verify your email and phone to continue.",
                                                        phone = phone
                                                    )
                                                )
                                            }
                                            else -> callback(dbResult)
                                        }
                                    }
                                )
                            }
                            .addOnFailureListener { e ->
                                callback(AppAuthResult.Error(e.message ?: "Failed to send verification email"))
                            }
                    } ?: callback(AppAuthResult.Error("Failed to create account"))
                } else {
                    val exception = task.exception
                    when {
                        exception is FirebaseAuthUserCollisionException -> {
                            callback(AppAuthResult.Error("Email already registered. Please sign in instead."))
                        }
                        else -> {
                            callback(AppAuthResult.Error(exception?.message ?: "Sign up failed"))
                        }
                    }
                }
            }
    }

    // Save user to database with caching
    private fun saveUserToDatabase(
        uid: String,
        email: String,
        phone: String,
        provider: String,
        isNewUser: Boolean,
        callback: (AppAuthResult) -> Unit
    ) {
        val emailVerified = auth.currentUser?.isEmailVerified == true
        val phoneE164 = normalizePhoneToE164(phone).orEmpty()
        val phoneVerified = !auth.currentUser?.phoneNumber.isNullOrBlank()
        val userMap = HashMap<String, Any>().apply {
            put("email", email.lowercase())
            put("phone", phone)
            put("phoneE164", phoneE164)
            put("provider", provider)
            put("createdAt", System.currentTimeMillis())
            put("lastLogin", System.currentTimeMillis())
            put("emailVerified", emailVerified)
            put("phoneVerified", phoneVerified)
            put("verificationUpdatedAt", System.currentTimeMillis())
        }

        database.reference.child("Users").child(uid)
            .setValue(userMap)
            .addOnSuccessListener {
                // Save email mapping
                val encodedEmail = encodeEmail(email)
                database.reference.child("Emails").child(encodedEmail)
                    .setValue(uid)
                    .addOnSuccessListener {
                        // Update cache
                        emailUserCache[email.lowercase()] = CachedUserData(
                            uid = uid,
                            provider = provider,
                            timestamp = System.currentTimeMillis()
                        )

                        callback(AppAuthResult.Success(isNewUser))
                    }
                    .addOnFailureListener { e ->
                        Log.e(tag, "Failed to save email mapping", e)
                        callback(AppAuthResult.Success(isNewUser))
                    }
            }
            .addOnFailureListener { e ->
                Log.e(tag, "Failed to save user", e)
                callback(AppAuthResult.Error("Failed to save user data: ${e.message}"))
            }
    }

    // Update existing user data
    private fun updateUserData(
        uid: String,
        provider: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val updates = mapOf<String, Any>(
            "lastLogin" to System.currentTimeMillis(),
            "provider" to provider, // Update last used provider
            "emailVerified" to (auth.currentUser?.isEmailVerified == true),
            "verificationUpdatedAt" to System.currentTimeMillis()
        )

        database.reference.child("Users").child(uid)
            .updateChildren(updates)
            .addOnSuccessListener {
                val currentUser = auth.currentUser
                if (currentUser != null) {
                    evaluateVerificationState(currentUser, false, callback)
                } else {
                    callback(AppAuthResult.Error("User not found"))
                }
            }
            .addOnFailureListener { e ->
                Log.e(tag, "Failed to update user", e)
                callback(AppAuthResult.Error("Failed to update user"))
            }
    }

    // Update user phone if needed
    private fun updateUserPhoneIfNeeded(
        uid: String,
        email: String,
        callback: (AppAuthResult) -> Unit
    ) {
        database.reference.child("Users").child(uid).get()
            .addOnSuccessListener { snapshot ->
                if (snapshot.exists()) {
                    // Update last login
                    snapshot.ref.child("lastLogin").setValue(System.currentTimeMillis())

                    // Check if email mapping exists
                    val encodedEmail = encodeEmail(email)
                    database.reference.child("Emails").child(encodedEmail)
                        .get()
                        .addOnSuccessListener { emailSnapshot ->
                            if (!emailSnapshot.exists()) {
                                // Create email mapping if missing
                                database.reference.child("Emails").child(encodedEmail)
                                    .setValue(uid)
                            }
                        }

                    val phone = snapshot.child("phone").getValue(String::class.java).orEmpty()
                    val persistedPhoneVerified = snapshot.child("phoneVerified").getValue(Boolean::class.java)
                    val updates = hashMapOf<String, Any>(
                        "emailVerified" to (auth.currentUser?.isEmailVerified == true),
                        "phoneVerified" to isPhoneCredentialVerified(auth.currentUser, persistedPhoneVerified),
                        "phoneE164" to normalizePhoneToE164(phone).orEmpty(),
                        "verificationUpdatedAt" to System.currentTimeMillis()
                    )
                    snapshot.ref.updateChildren(updates)

                    callback(AppAuthResult.Success(false))
                } else {
                    // User exists in Auth but not in DB - fix inconsistency
                    val provider = auth.currentUser?.providerData?.firstOrNull()?.providerId ?: "unknown"
                    saveUserToDatabase(uid, email, "", provider, false, callback)
                }
            }
            .addOnFailureListener {
                callback(AppAuthResult.Success(false))
            }
    }

    private fun evaluateVerificationState(
        user: FirebaseUser,
        isNewUser: Boolean,
        callback: (AppAuthResult) -> Unit
    ) {
        user.reload()
            .addOnSuccessListener {
                val emailVerified = user.isEmailVerified
                database.reference.child("Users").child(user.uid).get()
                    .addOnSuccessListener { snapshot ->
                        val phone = snapshot.child("phone").getValue(String::class.java).orEmpty()
                        val persistedPhoneVerified = snapshot.child("phoneVerified").getValue(Boolean::class.java)
                        val phoneVerified = isPhoneCredentialVerified(user, persistedPhoneVerified)
                        val phoneE164 = normalizePhoneToE164(phone).orEmpty()
                        val provider = snapshot.child("provider").getValue(String::class.java)
                            ?: user.providerData.firstOrNull { it.providerId != "firebase" }?.providerId
                            ?: "password"
                        val requiresPhoneVerification = provider == "password"

                        val updates = hashMapOf<String, Any>(
                            "emailVerified" to emailVerified,
                            "phoneVerified" to phoneVerified,
                            "phoneE164" to phoneE164,
                            "verificationUpdatedAt" to System.currentTimeMillis(),
                            "lastLogin" to System.currentTimeMillis()
                        )
                        snapshot.ref.updateChildren(updates)

                        when {
                            !emailVerified || (requiresPhoneVerification && !phoneVerified) -> {
                                callback(
                                    AppAuthResult.VerificationRequired(
                                        emailVerified = emailVerified,
                                        phoneVerified = phoneVerified,
                                        message = buildVerificationMessage(
                                            emailVerified,
                                            phoneVerified,
                                            requiresPhoneVerification
                                        ),
                                        phone = phone
                                    )
                                )
                            }
                            else -> callback(AppAuthResult.Success(isNewUser))
                        }
                    }
                    .addOnFailureListener { e ->
                        callback(AppAuthResult.Error(e.message ?: "Failed to validate account status"))
                    }
            }
            .addOnFailureListener { e ->
                callback(AppAuthResult.Error(e.message ?: "Failed to refresh account status"))
            }
    }

    private fun buildVerificationMessage(
        emailVerified: Boolean,
        phoneVerified: Boolean,
        requiresPhoneVerification: Boolean
    ): String {
        return when {
            !emailVerified && requiresPhoneVerification && !phoneVerified -> "Verify your email and phone to continue."
            !emailVerified -> "Please verify your email to continue."
            requiresPhoneVerification -> "Please verify your phone to continue."
            else -> "Verification required"
        }
    }

    private fun buildTempPassword(): String {
        return TEMP_PASSWORD_PREFIX + UUID.randomUUID().toString().replace("-", "").take(12)
    }

    private fun buildPhoneCallbacks(
        phoneE164: String,
        onCodeSent: (verificationId: String, token: PhoneAuthProvider.ForceResendingToken) -> Unit,
        onVerified: (AppAuthResult) -> Unit,
        onError: (String) -> Unit
    ): PhoneAuthProvider.OnVerificationStateChangedCallbacks {
        return object : PhoneAuthProvider.OnVerificationStateChangedCallbacks() {
            override fun onVerificationCompleted(credential: PhoneAuthCredential) {
                linkPhoneCredential(credential, onVerified)
            }

            override fun onVerificationFailed(e: FirebaseException) {
                onError(e.message ?: "Phone verification failed")
            }

            override fun onCodeSent(
                verificationId: String,
                token: PhoneAuthProvider.ForceResendingToken
            ) {
                onCodeSent(verificationId, token)
            }
        }
    }

    private fun linkPhoneCredential(
        credential: PhoneAuthCredential,
        callback: (AppAuthResult) -> Unit
    ) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(AppAuthResult.Error("User not logged in"))
            return
        }

        currentUser.linkWithCredential(credential)
            .addOnSuccessListener { authResult ->
                val resolvedUser = authResult.user ?: currentUser
                val phoneE164 = resolvedUser.phoneNumber ?: credential.smsCode?.let { null }
                persistVerifiedPhone(resolvedUser.uid, phoneE164, callback)
            }
            .addOnFailureListener { exception ->
                when (exception) {
                    is FirebaseAuthUserCollisionException,
                    is FirebaseAuthInvalidCredentialsException -> {
                        callback(AppAuthResult.Error("Invalid OTP or phone number already linked to another account"))
                    }
                    else -> {
                        // If phone is already linked to this user, treat as success and sync DB.
                        val alreadyLinked = currentUser.providerData.any { it.providerId == PhoneAuthProvider.PROVIDER_ID }
                        if (alreadyLinked) {
                            persistVerifiedPhone(currentUser.uid, currentUser.phoneNumber, callback)
                        } else {
                            callback(AppAuthResult.Error(exception.message ?: "Failed to verify phone"))
                        }
                    }
                }
            }
    }

    private fun persistVerifiedPhone(
        uid: String,
        phoneE164Input: String?,
        callback: (AppAuthResult) -> Unit
    ) {
        database.reference.child("Users").child(uid).get()
            .addOnSuccessListener { snapshot ->
                val existingPhone = snapshot.child("phone").getValue(String::class.java).orEmpty()
                val phoneE164 = phoneE164Input ?: normalizePhoneToE164(existingPhone).orEmpty()
                val localPhone = toLocalPhone(phoneE164).ifBlank { existingPhone }
                val updates = hashMapOf<String, Any>(
                    "phone" to localPhone,
                    "phoneE164" to phoneE164,
                    "phoneVerified" to true,
                    "verificationUpdatedAt" to System.currentTimeMillis()
                )

                snapshot.ref.updateChildren(updates)
                    .addOnSuccessListener {
                        val currentUser = auth.currentUser
                        if (currentUser != null) {
                            evaluateVerificationState(currentUser, false, callback)
                        } else {
                            callback(AppAuthResult.Success(false))
                        }
                    }
                    .addOnFailureListener { e ->
                        callback(AppAuthResult.Error(e.message ?: "Failed to save verified phone"))
                    }
            }
            .addOnFailureListener { e ->
                callback(AppAuthResult.Error(e.message ?: "Failed to load user profile"))
            }
    }

    private fun isPhoneCredentialVerified(user: FirebaseUser?, persistedPhoneVerified: Boolean?): Boolean {
        return (persistedPhoneVerified == true) && !user?.phoneNumber.isNullOrBlank()
    }

    private fun normalizePhoneToE164(rawPhone: String): String? {
        val trimmed = rawPhone.trim()
        if (trimmed.isEmpty()) return null

        return when {
            trimmed.startsWith("+") && trimmed.drop(1).all { it.isDigit() } -> trimmed
            trimmed.length == PHONE_LENGTH && trimmed.all { it.isDigit() } -> "+91$trimmed"
            else -> null
        }
    }

    private fun toLocalPhone(phoneE164: String): String {
        val digits = phoneE164.filter { it.isDigit() }
        return if (digits.length >= PHONE_LENGTH) digits.takeLast(PHONE_LENGTH) else digits
    }

    // Check if email exists in database with caching
    private suspend fun checkEmailExists(email: String): CachedUserData? {
        val lowerEmail = email.lowercase()

        // Check cache first
        emailUserCache[lowerEmail]?.let { cachedData ->
            if (cachedData.isValid()) {
                return cachedData
            }
        }

        return try {
            val encodedEmail = encodeEmail(email)
            val snapshot = database.reference
                .child("Emails")
                .child(encodedEmail)
                .get()
                .await()

            if (snapshot.exists()) {
                val uid = snapshot.getValue(String::class.java) ?: return null

                // Get user data to know provider
                val userSnapshot = database.reference
                    .child("Users")
                    .child(uid)
                    .get()
                    .await()

                if (userSnapshot.exists()) {
                    val provider = userSnapshot.child("provider").value as? String ?: "unknown"
                    val cachedData = CachedUserData(
                        uid = uid,
                        provider = provider,
                        timestamp = System.currentTimeMillis()
                    )
                    emailUserCache[lowerEmail] = cachedData
                    cachedData
                } else {
                    null
                }
            } else {
                null
            }
        } catch (e: Exception) {
            Log.e(tag, "Error checking email", e)
            null
        }
    }

    // Check if phone number already exists in database
    private suspend fun checkPhoneExists(phone: String, currentUid: String? = null): Boolean {
        if (phone.isEmpty()) return false

        val normalizedPhone = normalizePhoneToE164(phone) ?: return false
        val localPhone = toLocalPhone(normalizedPhone)

        return try {
            val byE164Snapshot = database.reference.child("Users")
                .orderByChild("phoneE164")
                .equalTo(normalizedPhone)
                .get()
                .await()

            val hasOtherAccountByE164 = byE164Snapshot.children.any { snapshot ->
                val uid = snapshot.key
                uid != null && uid != currentUid
            }

            if (hasOtherAccountByE164) {
                return true
            }

            val byLocalPhoneSnapshot = database.reference.child("Users")
                .orderByChild("phone")
                .equalTo(localPhone)
                .get()
                .await()

            byLocalPhoneSnapshot.children.any { snapshot ->
                val uid = snapshot.key
                uid != null && uid != currentUid
            }
        } catch (e: Exception) {
            Log.e(tag, "Error checking phone", e)
            false
        }
    }


    private fun encodeEmail(email: String): String {
        return email.lowercase()
            .replace(".", "_")
            .replace("@", "_")
    }

    fun signOut() {
        auth.signOut()
    }

    fun getCurrentUser(): FirebaseUser? {
        return auth.currentUser
    }

    fun isUserLoggedIn(): Boolean {
        return auth.currentUser != null
    }

    // Clear cache (call on logout)
    fun clearCache() {
        emailUserCache.clear()
    }
}

package com.kartik.aistudyassistant.data.repository

import android.app.Activity
import android.content.Context
import android.util.Log
import androidx.credentials.*
import androidx.credentials.exceptions.GetCredentialException
import com.kartik.aistudyassistant.data.model.AuthResult as AppAuthResult
import com.google.android.libraries.identity.googleid.*
import com.google.firebase.FirebaseException
import com.google.firebase.auth.*
import com.google.firebase.database.FirebaseDatabase
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext
import java.util.concurrent.TimeUnit
import java.util.UUID

class AuthManager(private val context: Context) {

    private val auth: FirebaseAuth = FirebaseAuth.getInstance()
    private val credentialManager = CredentialManager.create(context)
    private val database = FirebaseDatabase.getInstance()
    private val tag = "AuthManager"

    companion object {
        // Cache for user existence checks
        private val emailUserCache = mutableMapOf<String, CachedUserData>()
        private const val CACHE_DURATION = 5 * 60 * 1000 // 5 minutes
        private const val PHONE_LENGTH = 10
        private const val OTP_TIMEOUT_SECONDS = 60L
        private const val TEMP_PASSWORD_PREFIX = "Tmp#"

        data class CachedUserData(
            val uid: String,
            val provider: String,
            val timestamp: Long
        ) {
            fun isValid(): Boolean = System.currentTimeMillis() - timestamp < CACHE_DURATION
        }

    }

    fun checkCurrentUserVerification(callback: (AppAuthResult) -> Unit) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(AppAuthResult.Error("User not logged in"))
            return
        }

        evaluateVerificationState(currentUser, false, callback)
    }

    fun sendEmailVerificationForCurrentUser(callback: (AppAuthResult) -> Unit) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(AppAuthResult.Error("User not logged in"))
            return
        }

        currentUser.sendEmailVerification()
            .addOnSuccessListener {
                callback(AppAuthResult.Success(false))
            }
            .addOnFailureListener { e ->
                callback(AppAuthResult.Error(e.message ?: "Failed to send verification email"))
            }
    }

    fun startPendingEmailVerification(email: String, callback: (AppAuthResult) -> Unit) {
        val normalizedEmail = email.trim().lowercase()
        if (normalizedEmail.isBlank()) {
            callback(AppAuthResult.Error("Email is required"))
            return
        }

        CoroutineScope(Dispatchers.IO).launch {
            try {
                val existingUserData = checkEmailExists(normalizedEmail)
                if (existingUserData != null) {
                    withContext(Dispatchers.Main) {
                        callback(
                            AppAuthResult.Error(
                                "An account already exists with this email using ${existingUserData.provider}."
                            )
                        )
                    }
                    return@launch
                }

                withContext(Dispatchers.Main) {
                    val currentUser = auth.currentUser
                    if (currentUser != null && currentUser.email.equals(normalizedEmail, ignoreCase = true)) {
                        sendEmailVerificationForCurrentUser(callback)
                    } else {
                        auth.signOut()
                        val tempPassword = buildTempPassword()
                        auth.createUserWithEmailAndPassword(normalizedEmail, tempPassword)
                            .addOnSuccessListener {
                                auth.currentUser?.sendEmailVerification()
                                    ?.addOnSuccessListener { callback(AppAuthResult.Success(true)) }
                                    ?.addOnFailureListener { e ->
                                        callback(
                                            AppAuthResult.Error(
                                                e.message ?: "Failed to send verification email"
                                            )
                                        )
                                    }
                            }
                            .addOnFailureListener { e ->
                                callback(AppAuthResult.Error(e.message ?: "Unable to start email verification"))
                            }
                    }
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error(e.message ?: "Unable to start email verification"))
                }
            }
        }
    }

    fun refreshEmailVerificationStatus(callback: (Boolean, String?) -> Unit) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(false, "Please verify email first")
            return
        }

        currentUser.reload()
            .addOnSuccessListener {
                callback(currentUser.isEmailVerified, null)
            }
            .addOnFailureListener { e ->
                callback(false, e.message ?: "Failed to refresh email verification")
            }
    }

    fun completeVerifiedEmailSignUp(
        phone: String,
        password: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(AppAuthResult.Error("Please verify email first"))
            return
        }

        if (!currentUser.isEmailVerified) {
            callback(AppAuthResult.Error("Email is not verified yet"))
            return
        }

        val verifiedPhone = currentUser.phoneNumber
        val resolvedPhone = if (!verifiedPhone.isNullOrBlank()) {
            toLocalPhone(verifiedPhone)
        } else {
            phone.trim()
        }

        CoroutineScope(Dispatchers.IO).launch {
            val phoneExists = checkPhoneExists(resolvedPhone, currentUser.uid)
            if (phoneExists) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error("This phone number is already registered with another account."))
                }
                return@launch
            }

            withContext(Dispatchers.Main) {
                currentUser.updatePassword(password)
                    .addOnSuccessListener {
                        val email = currentUser.email.orEmpty()
                        saveUserToDatabase(
                            uid = currentUser.uid,
                            email = email,
                            phone = resolvedPhone,
                            provider = "password",
                            isNewUser = true,
                            callback = { dbResult ->
                                when (dbResult) {
                                    is AppAuthResult.Success -> evaluateVerificationState(currentUser, true, callback)
                                    else -> callback(dbResult)
                                }
                            }
                        )
                    }
                    .addOnFailureListener { e ->
                        callback(AppAuthResult.Error(e.message ?: "Failed to finalize account setup"))
                    }
            }
        }
    }

    fun startPhoneVerification(
        activity: Activity,
        rawPhone: String,
        onCodeSent: (verificationId: String, token: PhoneAuthProvider.ForceResendingToken) -> Unit,
        onVerified: (AppAuthResult) -> Unit,
        onError: (String) -> Unit
    ) {
        val phoneE164 = normalizePhoneToE164(rawPhone)
        if (phoneE164 == null) {
            onError("Enter a valid phone number")
            return
        }

        val callbacks = buildPhoneCallbacks(phoneE164, onCodeSent, onVerified, onError)
        val options = PhoneAuthOptions.newBuilder(auth)
            .setPhoneNumber(phoneE164)
            .setTimeout(OTP_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .setActivity(activity)
            .setCallbacks(callbacks)
            .build()

        PhoneAuthProvider.verifyPhoneNumber(options)
    }

    fun resendPhoneVerification(
        activity: Activity,
        rawPhone: String,
        token: PhoneAuthProvider.ForceResendingToken,
        onCodeSent: (verificationId: String, resendToken: PhoneAuthProvider.ForceResendingToken) -> Unit,
        onVerified: (AppAuthResult) -> Unit,
        onError: (String) -> Unit
    ) {
        val phoneE164 = normalizePhoneToE164(rawPhone)
        if (phoneE164 == null) {
            onError("Enter a valid phone number")
            return
        }

        val callbacks = buildPhoneCallbacks(phoneE164, onCodeSent, onVerified, onError)
        val options = PhoneAuthOptions.newBuilder(auth)
            .setPhoneNumber(phoneE164)
            .setTimeout(OTP_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .setActivity(activity)
            .setCallbacks(callbacks)
            .setForceResendingToken(token)
            .build()

        PhoneAuthProvider.verifyPhoneNumber(options)
    }

    fun verifyPhoneCode(
        verificationId: String,
        code: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val credential = PhoneAuthProvider.getCredential(verificationId, code)
        linkPhoneCredential(credential, callback)
    }

    fun getCurrentUserStoredPhone(callback: (String?) -> Unit) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(null)
            return
        }

        database.reference.child("Users").child(currentUser.uid).child("phone")
            .get()
            .addOnSuccessListener { snapshot ->
                callback(snapshot.getValue(String::class.java))
            }
            .addOnFailureListener {
                callback(null)
            }
    }

    // Google Sign-In
    fun signInWithGoogle(callback: (AppAuthResult) -> Unit) {
        val googleIdOption = GetGoogleIdOption.Builder()
            .setFilterByAuthorizedAccounts(false)
            .setServerClientId(
                context.getString(com.kartik.aistudyassistant.R.string.default_web_client_id)
            )
            .build()

        val request = GetCredentialRequest.Builder()
            .addCredentialOption(googleIdOption)
            .build()

        CoroutineScope(Dispatchers.Main).launch {
            try {
                val result = credentialManager.getCredential(
                    request = request,
                    context = context
                )

                val credential = result.credential

                if (credential is CustomCredential &&
                    credential.type == GoogleIdTokenCredential.TYPE_GOOGLE_ID_TOKEN_CREDENTIAL
                ) {
                    val googleIdTokenCredential =
                        GoogleIdTokenCredential.createFrom(credential.data)

                    handleProviderSignIn(
                        idToken = googleIdTokenCredential.idToken,
                        email = googleIdTokenCredential.id,
                        callback = callback
                    )
                } else {
                    callback(AppAuthResult.Error("Invalid credential type"))
                }
            } catch (e: GetCredentialException) {
                if (e.message?.contains("cancelled", ignoreCase = true) == true) {
                    callback(AppAuthResult.Cancelled)
                } else {
                    callback(AppAuthResult.Error(e.message))
                }
            }
        }
    }

    // GitHub Sign-In
    fun signInWithGithub(activity: Activity, callback: (AppAuthResult) -> Unit) {
        val provider = OAuthProvider.newBuilder("github.com")
            .addCustomParameter("allow_signup", "true")
            .build()

        auth.startActivityForSignInWithProvider(activity, provider)
            .addOnSuccessListener { authResult ->
                val user = authResult.user
                user?.let {
                    val email = it.email?.trim()?.lowercase().orEmpty()
                    CoroutineScope(Dispatchers.IO).launch {
                        try {
                            val existingUserData = if (email.isBlank()) null else checkEmailExists(email)

                            withContext(Dispatchers.Main) {
                                if (existingUserData != null && existingUserData.uid != it.uid) {
                                    callback(AppAuthResult.Error(
                                        "This email is already registered with ${existingUserData.provider}. " +
                                                "Please sign in with ${existingUserData.provider} first."
                                    ))
                                } else {
                                    saveUserToDatabase(
                                        uid = it.uid,
                                        email = email,
                                        phone = "",
                                        provider = "github.com",
                                        isNewUser = authResult.additionalUserInfo?.isNewUser ?: false,
                                        callback = { dbResult ->
                                            when (dbResult) {
                                                is AppAuthResult.Success -> {
                                                    evaluateVerificationState(
                                                        it,
                                                        authResult.additionalUserInfo?.isNewUser ?: false,
                                                        callback
                                                    )
                                                }
                                                else -> callback(dbResult)
                                            }
                                        }
                                    )
                                }
                            }
                        } catch (e: Exception) {
                            withContext(Dispatchers.Main) {
                                callback(AppAuthResult.Error(e.message))
                            }
                        }
                    }
                } ?: callback(AppAuthResult.Error("Failed to get user info"))
            }
            .addOnFailureListener { e ->
                if (e.message?.contains("cancelled", ignoreCase = true) == true) {
                    callback(AppAuthResult.Cancelled)
                } else {
                    callback(AppAuthResult.Error(e.message ?: "GitHub sign-in failed"))
                }
            }
    }

    // Email/Password Sign Up
    fun signUpWithEmail(email: String, password: String, phone: String, callback: (AppAuthResult) -> Unit) {
        CoroutineScope(Dispatchers.IO).launch {
            try {
                // Check if email exists in our database first
                val existingUserData = checkEmailExists(email)
                if (existingUserData != null) {
                    withContext(Dispatchers.Main) {
                        callback(AppAuthResult.Error(
                            "An account already exists with this email using ${existingUserData.provider}."
                        ))
                    }
                    return@launch
                }

                // Check if phone exists (Problem #5 fix)
                val phoneExists = checkPhoneExists(phone)
                if (phoneExists) {
                    withContext(Dispatchers.Main) {
                        callback(AppAuthResult.Error("This phone number is already registered with another account."))
                    }
                    return@launch
                }

                // Create new account with password
                withContext(Dispatchers.Main) {
                    createEmailAccount(email, password, phone, callback)
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error(e.message))
                }
            }
        }
    }

    // Email/Password Sign In
    fun signInWithEmail(email: String, password: String, callback: (AppAuthResult) -> Unit) {
        auth.signInWithEmailAndPassword(email, password)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    val user = auth.currentUser
                    user?.let {
                        updateUserPhoneIfNeeded(it.uid, email) { updateResult ->
                            when (updateResult) {
                                is AppAuthResult.Error -> callback(updateResult)
                                else -> evaluateVerificationState(it, false, callback)
                            }
                        }
                    } ?: callback(AppAuthResult.Error("User not found"))
                } else {
                    val exception = task.exception
                    when {
                        exception is FirebaseAuthInvalidUserException -> {
                            callback(AppAuthResult.Error("No account found with this email"))
                        }
                        exception is FirebaseAuthInvalidCredentialsException -> {
                            callback(AppAuthResult.Error("Invalid password"))
                        }
                        else -> {
                            callback(AppAuthResult.Error(exception?.message ?: "Sign in failed"))
                        }
                    }
                }
            }
    }

    // Handle provider sign-in (Google)
    private fun handleProviderSignIn(
        idToken: String,
        email: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val provider = "google.com"
        val normalizedEmail = email.trim().lowercase()
        if (normalizedEmail.isBlank()) {
            callback(AppAuthResult.Error("Unable to read Google account email"))
            return
        }

        CoroutineScope(Dispatchers.IO).launch {
            try {
                val existingUserData = checkEmailExists(normalizedEmail)

                withContext(Dispatchers.Main) {
                    if (existingUserData != null) {
                        linkProviderToExistingAccount(
                            idToken = idToken,
                            provider = provider,
                            existingUid = existingUserData.uid,
                            callback = callback
                        )
                    } else {
                        createProviderAccount(
                            idToken = idToken,
                            provider = provider,
                            email = normalizedEmail,
                            callback = callback
                        )
                    }
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error(e.message))
                }
            }
        }
    }

    private fun linkProviderToExistingAccount(
        idToken: String,
        provider: String,
        existingUid: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val credential = when (provider) {
            "google.com" -> GoogleAuthProvider.getCredential(idToken, null)
            else -> null
        }

        if (credential == null) {
            callback(AppAuthResult.Error("Invalid provider"))
            return
        }

        // Try to sign in with the new credential
        auth.signInWithCredential(credential)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    // Successfully signed in with new provider
                    val user = auth.currentUser
                    if (user?.uid == existingUid) {
                        // Same account, already linked
                        updateUserData(user.uid, provider, callback)
                    } else {
                        // Different account, need to link
                        linkAccounts(user, callback)
                    }
                } else {
                    val exception = task.exception
                    when {
                        exception is FirebaseAuthUserCollisionException -> {
                            // Email already used with another provider
                            handleAccountCollision(exception, provider, callback)
                        }
                        else -> {
                            callback(AppAuthResult.Error(exception?.message ?: "Authentication failed"))
                        }
                    }
                }
            }
    }

    // Handle account collision (email exists with different provider)
    private fun handleAccountCollision(
        exception: FirebaseAuthUserCollisionException,
        newProvider: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val email = exception.email ?: ""

        CoroutineScope(Dispatchers.IO).launch {
            try {
                val existingUserData = checkEmailExists(email)

                withContext(Dispatchers.Main) {
                    if (existingUserData != null) {
                        callback(AppAuthResult.Error(
                            "This email is already registered with ${existingUserData.provider}. " +
                                    "Please sign in with ${existingUserData.provider} first, then you can link your $newProvider account."
                        ))
                    } else {
                        callback(AppAuthResult.Error("Email already in use with another provider"))
                    }
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    callback(AppAuthResult.Error(e.message))
                }
            }
        }
    }

    private fun linkAccounts(
        newUser: FirebaseUser?,
        callback: (AppAuthResult) -> Unit
    ) {
        if (newUser == null) {
            callback(AppAuthResult.Error("Failed to link accounts"))
            return
        }

        // Sign in with existing account first
        // This is complex - in a real app, you'd prompt user to sign in with original provider
        // For now, we'll delete the new account and ask user to sign in with original provider
        newUser.delete()
            .addOnCompleteListener {
                callback(AppAuthResult.Error(
                    "Please sign in with your original provider first, then link this provider."
                ))
            }
    }

    // Create account with provider (Google)
    private fun createProviderAccount(
        idToken: String,
        provider: String,
        email: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val credential = when (provider) {
            "google.com" -> GoogleAuthProvider.getCredential(idToken, null)
            else -> null
        }

        credential?.let {
            auth.signInWithCredential(it)
                .addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        val user = auth.currentUser
                        user?.let {
                            saveUserToDatabase(
                                uid = it.uid,
                                email = email,
                                phone = "",
                                provider = provider,
                                isNewUser = true,
                                callback = { dbResult ->
                                    when (dbResult) {
                                        is AppAuthResult.Success -> evaluateVerificationState(it, true, callback)
                                        else -> callback(dbResult)
                                    }
                                }
                            )
                        } ?: callback(AppAuthResult.Error("Failed to create account"))
                    } else {
                        callback(AppAuthResult.Error(task.exception?.message ?: "Authentication failed"))
                    }
                }
        }
    }

    // Create email/password account
    private fun createEmailAccount(
        email: String,
        password: String,
        phone: String,
        callback: (AppAuthResult) -> Unit
    ) {
        auth.createUserWithEmailAndPassword(email, password)
            .addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    val user = auth.currentUser
                    user?.let { firebaseUser ->
                        firebaseUser.sendEmailVerification()
                            .addOnSuccessListener {
                                saveUserToDatabase(
                                    uid = firebaseUser.uid,
                                    email = email,
                                    phone = phone,
                                    provider = "password",
                                    isNewUser = true,
                                    callback = { dbResult ->
                                        when (dbResult) {
                                            is AppAuthResult.Success -> {
                                                callback(
                                                    AppAuthResult.VerificationRequired(
                                                        emailVerified = false,
                                                        phoneVerified = false,
                                                        message = "Verify your email and phone to continue.",
                                                        phone = phone
                                                    )
                                                )
                                            }
                                            else -> callback(dbResult)
                                        }
                                    }
                                )
                            }
                            .addOnFailureListener { e ->
                                callback(AppAuthResult.Error(e.message ?: "Failed to send verification email"))
                            }
                    } ?: callback(AppAuthResult.Error("Failed to create account"))
                } else {
                    val exception = task.exception
                    when {
                        exception is FirebaseAuthUserCollisionException -> {
                            callback(AppAuthResult.Error("Email already registered. Please sign in instead."))
                        }
                        else -> {
                            callback(AppAuthResult.Error(exception?.message ?: "Sign up failed"))
                        }
                    }
                }
            }
    }

    // Save user to database with caching
    private fun saveUserToDatabase(
        uid: String,
        email: String,
        phone: String,
        provider: String,
        isNewUser: Boolean,
        callback: (AppAuthResult) -> Unit
    ) {
        val normalizedEmail = email.trim().lowercase()
        val emailVerified = auth.currentUser?.isEmailVerified == true
        val phoneE164 = normalizePhoneToE164(phone).orEmpty()
        val phoneVerified = !auth.currentUser?.phoneNumber.isNullOrBlank()
        val userMap = HashMap<String, Any>().apply {
            put("email", normalizedEmail)
            put("phone", phone)
            put("phoneE164", phoneE164)
            put("provider", provider)
            put("createdAt", System.currentTimeMillis())
            put("lastLogin", System.currentTimeMillis())
            put("emailVerified", emailVerified)
            put("phoneVerified", phoneVerified)
            put("verificationUpdatedAt", System.currentTimeMillis())
        }

        database.reference.child("Users").child(uid)
            .setValue(userMap)
            .addOnSuccessListener {
                if (normalizedEmail.isBlank()) {
                    callback(AppAuthResult.Success(isNewUser))
                    return@addOnSuccessListener
                }

                val encodedEmail = encodeEmail(normalizedEmail)
                database.reference.child("Emails").child(encodedEmail)
                    .setValue(uid)
                    .addOnSuccessListener {
                        emailUserCache[normalizedEmail] = CachedUserData(
                            uid = uid,
                            provider = provider,
                            timestamp = System.currentTimeMillis()
                        )

                        callback(AppAuthResult.Success(isNewUser))
                    }
                    .addOnFailureListener { e ->
                        Log.e(tag, "Failed to save email mapping", e)
                        callback(AppAuthResult.Success(isNewUser))
                    }
            }
            .addOnFailureListener { e ->
                Log.e(tag, "Failed to save user", e)
                callback(AppAuthResult.Error("Failed to save user data: ${e.message}"))
            }
    }

    // Update existing user data
    private fun updateUserData(
        uid: String,
        provider: String,
        callback: (AppAuthResult) -> Unit
    ) {
        val updates = mapOf<String, Any>(
            "lastLogin" to System.currentTimeMillis(),
            "provider" to provider, // Update last used provider
            "emailVerified" to (auth.currentUser?.isEmailVerified == true),
            "verificationUpdatedAt" to System.currentTimeMillis()
        )

        database.reference.child("Users").child(uid)
            .updateChildren(updates)
            .addOnSuccessListener {
                val currentUser = auth.currentUser
                if (currentUser != null) {
                    evaluateVerificationState(currentUser, false, callback)
                } else {
                    callback(AppAuthResult.Error("User not found"))
                }
            }
            .addOnFailureListener { e ->
                Log.e(tag, "Failed to update user", e)
                callback(AppAuthResult.Error("Failed to update user"))
            }
    }

    // Update user phone if needed
    private fun updateUserPhoneIfNeeded(
        uid: String,
        email: String,
        callback: (AppAuthResult) -> Unit
    ) {
        database.reference.child("Users").child(uid).get()
            .addOnSuccessListener { snapshot ->
                if (snapshot.exists()) {
                    // Update last login
                    snapshot.ref.child("lastLogin").setValue(System.currentTimeMillis())

                    // Check if email mapping exists
                    val encodedEmail = encodeEmail(email)
                    database.reference.child("Emails").child(encodedEmail)
                        .get()
                        .addOnSuccessListener { emailSnapshot ->
                            if (!emailSnapshot.exists()) {
                                // Create email mapping if missing
                                database.reference.child("Emails").child(encodedEmail)
                                    .setValue(uid)
                            }
                        }

                    val phone = snapshot.child("phone").getValue(String::class.java).orEmpty()
                    val persistedPhoneVerified = snapshot.child("phoneVerified").getValue(Boolean::class.java)
                    val updates = hashMapOf<String, Any>(
                        "emailVerified" to (auth.currentUser?.isEmailVerified == true),
                        "phoneVerified" to isPhoneCredentialVerified(auth.currentUser, persistedPhoneVerified),
                        "phoneE164" to normalizePhoneToE164(phone).orEmpty(),
                        "verificationUpdatedAt" to System.currentTimeMillis()
                    )
                    snapshot.ref.updateChildren(updates)

                    callback(AppAuthResult.Success(false))
                } else {
                    // User exists in Auth but not in DB - fix inconsistency
                    val provider = auth.currentUser?.providerData?.firstOrNull()?.providerId ?: "unknown"
                    saveUserToDatabase(uid, email, "", provider, false, callback)
                }
            }
            .addOnFailureListener {
                callback(AppAuthResult.Success(false))
            }
    }

    private fun evaluateVerificationState(
        user: FirebaseUser,
        isNewUser: Boolean,
        callback: (AppAuthResult) -> Unit
    ) {
        user.reload()
            .addOnSuccessListener {
                val emailVerified = user.isEmailVerified
                database.reference.child("Users").child(user.uid).get()
                    .addOnSuccessListener { snapshot ->
                        val phone = snapshot.child("phone").getValue(String::class.java).orEmpty()
                        val persistedPhoneVerified = snapshot.child("phoneVerified").getValue(Boolean::class.java)
                        val phoneVerified = isPhoneCredentialVerified(user, persistedPhoneVerified)
                        val phoneE164 = normalizePhoneToE164(phone).orEmpty()
                        val snapshotProvider = snapshot.child("provider").getValue(String::class.java)
                        val provider = resolvePrimaryProvider(user, snapshotProvider)
                        val requiresStrictVerification = !isSocialProvider(provider)

                        val updates = hashMapOf<String, Any>(
                            "emailVerified" to emailVerified,
                            "phoneVerified" to phoneVerified,
                            "phoneE164" to phoneE164,
                            "verificationUpdatedAt" to System.currentTimeMillis(),
                            "lastLogin" to System.currentTimeMillis()
                        )
                        snapshot.ref.updateChildren(updates)

                        when {
                            requiresStrictVerification && (!emailVerified || !phoneVerified) -> {
                                callback(
                                    AppAuthResult.VerificationRequired(
                                        emailVerified = emailVerified,
                                        phoneVerified = phoneVerified,
                                        message = buildVerificationMessage(emailVerified, phoneVerified, true),
                                        phone = phone
                                    )
                                )
                            }
                            else -> callback(AppAuthResult.Success(isNewUser))
                        }
                    }
                    .addOnFailureListener { e ->
                        callback(AppAuthResult.Error(e.message ?: "Failed to validate account status"))
                    }
            }
            .addOnFailureListener { e ->
                callback(AppAuthResult.Error(e.message ?: "Failed to refresh account status"))
            }
    }

    private fun buildVerificationMessage(
        emailVerified: Boolean,
        phoneVerified: Boolean,
        requiresPhoneVerification: Boolean
    ): String {
        return when {
            !emailVerified && requiresPhoneVerification && !phoneVerified -> "Verify your email and phone to continue."
            !emailVerified -> "Please verify your email to continue."
            requiresPhoneVerification -> "Please verify your phone to continue."
            else -> "Verification required"
        }
    }

    private fun buildTempPassword(): String {
        return TEMP_PASSWORD_PREFIX + UUID.randomUUID().toString().replace("-", "").take(12)
    }

    private fun buildPhoneCallbacks(
        phoneE164: String,
        onCodeSent: (verificationId: String, token: PhoneAuthProvider.ForceResendingToken) -> Unit,
        onVerified: (AppAuthResult) -> Unit,
        onError: (String) -> Unit
    ): PhoneAuthProvider.OnVerificationStateChangedCallbacks {
        return object : PhoneAuthProvider.OnVerificationStateChangedCallbacks() {
            override fun onVerificationCompleted(credential: PhoneAuthCredential) {
                linkPhoneCredential(credential, onVerified)
            }

            override fun onVerificationFailed(e: FirebaseException) {
                onError(e.message ?: "Phone verification failed")
            }

            override fun onCodeSent(
                verificationId: String,
                token: PhoneAuthProvider.ForceResendingToken
            ) {
                onCodeSent(verificationId, token)
            }
        }
    }

    private fun linkPhoneCredential(
        credential: PhoneAuthCredential,
        callback: (AppAuthResult) -> Unit
    ) {
        val currentUser = auth.currentUser
        if (currentUser == null) {
            callback(AppAuthResult.Error("User not logged in"))
            return
        }

        currentUser.linkWithCredential(credential)
            .addOnSuccessListener { authResult ->
                val resolvedUser = authResult.user ?: currentUser
                val phoneE164 = resolvedUser.phoneNumber ?: credential.smsCode?.let { null }
                persistVerifiedPhone(resolvedUser.uid, phoneE164, callback)
            }
            .addOnFailureListener { exception ->
                when (exception) {
                    is FirebaseAuthUserCollisionException,
                    is FirebaseAuthInvalidCredentialsException -> {
                        callback(AppAuthResult.Error("Invalid OTP or phone number already linked to another account"))
                    }
                    else -> {
                        // If phone is already linked to this user, treat as success and sync DB.
                        val alreadyLinked = currentUser.providerData.any { it.providerId == PhoneAuthProvider.PROVIDER_ID }
                        if (alreadyLinked) {
                            persistVerifiedPhone(currentUser.uid, currentUser.phoneNumber, callback)
                        } else {
                            callback(AppAuthResult.Error(exception.message ?: "Failed to verify phone"))
                        }
                    }
                }
            }
    }

    private fun persistVerifiedPhone(
        uid: String,
        phoneE164Input: String?,
        callback: (AppAuthResult) -> Unit
    ) {
        database.reference.child("Users").child(uid).get()
            .addOnSuccessListener { snapshot ->
                val existingPhone = snapshot.child("phone").getValue(String::class.java).orEmpty()
                val phoneE164 = phoneE164Input ?: normalizePhoneToE164(existingPhone).orEmpty()
                val localPhone = toLocalPhone(phoneE164).ifBlank { existingPhone }
                val updates = hashMapOf<String, Any>(
                    "phone" to localPhone,
                    "phoneE164" to phoneE164,
                    "phoneVerified" to true,
                    "verificationUpdatedAt" to System.currentTimeMillis()
                )

                snapshot.ref.updateChildren(updates)
                    .addOnSuccessListener {
                        val currentUser = auth.currentUser
                        if (currentUser != null) {
                            evaluateVerificationState(currentUser, false, callback)
                        } else {
                            callback(AppAuthResult.Success(false))
                        }
                    }
                    .addOnFailureListener { e ->
                        callback(AppAuthResult.Error(e.message ?: "Failed to save verified phone"))
                    }
            }
            .addOnFailureListener { e ->
                callback(AppAuthResult.Error(e.message ?: "Failed to load user profile"))
            }
    }

    private fun isPhoneCredentialVerified(user: FirebaseUser?, persistedPhoneVerified: Boolean?): Boolean {
        return (persistedPhoneVerified == true) && !user?.phoneNumber.isNullOrBlank()
    }

    private fun normalizePhoneToE164(rawPhone: String): String? {
        val trimmed = rawPhone.trim()
        if (trimmed.isEmpty()) return null

        return when {
            trimmed.startsWith("+") && trimmed.drop(1).all { it.isDigit() } -> trimmed
            trimmed.length == PHONE_LENGTH && trimmed.all { it.isDigit() } -> "+91$trimmed"
            else -> null
        }
    }

    private fun toLocalPhone(phoneE164: String): String {
        val digits = phoneE164.filter { it.isDigit() }
        return if (digits.length >= PHONE_LENGTH) digits.takeLast(PHONE_LENGTH) else digits
    }

    private fun isSocialProvider(provider: String): Boolean {
        return provider == "google.com" || provider == "github.com"
    }

    private fun resolvePrimaryProvider(user: FirebaseUser, snapshotProvider: String?): String {
        val providers = user.providerData
            .map { it.providerId }
            .filter { it != "firebase" }

        return when {
            providers.any { it == "google.com" } -> "google.com"
            providers.any { it == "github.com" } -> "github.com"
            providers.any { it == "password" } -> "password"
            !snapshotProvider.isNullOrBlank() && snapshotProvider != "unknown" -> snapshotProvider
            else -> "password"
        }
    }

    // Check if email exists in database with caching
    private suspend fun checkEmailExists(email: String): CachedUserData? {
        val lowerEmail = email.lowercase()
        if (lowerEmail.isBlank()) return null

        // Check cache first
        emailUserCache[lowerEmail]?.let { cachedData ->
            if (cachedData.isValid()) {
                return cachedData
            }
        }

        return try {
            val encodedEmail = encodeEmail(email)
            val snapshot = database.reference
                .child("Emails")
                .child(encodedEmail)
                .get()
                .await()

            if (snapshot.exists()) {
                val uid = snapshot.getValue(String::class.java) ?: return null

                // Get user data to know provider
                val userSnapshot = database.reference
                    .child("Users")
                    .child(uid)
                    .get()
                    .await()

                if (userSnapshot.exists()) {
                    val provider = userSnapshot.child("provider").value as? String ?: "unknown"
                    val cachedData = CachedUserData(
                        uid = uid,
                        provider = provider,
                        timestamp = System.currentTimeMillis()
                    )
                    emailUserCache[lowerEmail] = cachedData
                    cachedData
                } else {
                    null
                }
            } else {
                null
            }
        } catch (e: Exception) {
            Log.e(tag, "Error checking email", e)
            null
        }
    }

    // Check if phone number already exists in database
    private suspend fun checkPhoneExists(phone: String, currentUid: String? = null): Boolean {
        if (phone.isEmpty()) return false

        val normalizedPhone = normalizePhoneToE164(phone) ?: return false
        val localPhone = toLocalPhone(normalizedPhone)

        return try {
            val byE164Snapshot = database.reference.child("Users")
                .orderByChild("phoneE164")
                .equalTo(normalizedPhone)
                .get()
                .await()

            val hasOtherAccountByE164 = byE164Snapshot.children.any { snapshot ->
                val uid = snapshot.key
                uid != null && uid != currentUid
            }

            if (hasOtherAccountByE164) {
                return true
            }

            val byLocalPhoneSnapshot = database.reference.child("Users")
                .orderByChild("phone")
                .equalTo(localPhone)
                .get()
                .await()

            byLocalPhoneSnapshot.children.any { snapshot ->
                val uid = snapshot.key
                uid != null && uid != currentUid
            }
        } catch (e: Exception) {
            Log.e(tag, "Error checking phone", e)
            false
        }
    }


    private fun encodeEmail(email: String): String {
        return email.lowercase()
            .replace(".", "_")
            .replace("@", "_")
    }

    fun signOut() {
        auth.signOut()
    }

    fun getCurrentUser(): FirebaseUser? {
        return auth.currentUser
    }

    fun isUserLoggedIn(): Boolean {
        return auth.currentUser != null
    }

    // Clear cache (call on logout)
    fun clearCache() {
        emailUserCache.clear()
    }
}

package com.kartik.aistudyassistant.ui.auth

import android.content.Intent
import android.os.Bundle
import android.util.Patterns
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import com.kartik.aistudyassistant.data.local.UserProfilePrefs
import com.kartik.aistudyassistant.data.repository.AuthManager
import com.kartik.aistudyassistant.R
import com.google.android.material.button.MaterialButton
import com.google.firebase.auth.FirebaseAuth
import com.kartik.aistudyassistant.data.model.AuthResult
import com.kartik.aistudyassistant.ui.home.MainActivity
import com.google.android.material.bottomsheet.BottomSheetDialog
import com.google.android.material.dialog.MaterialAlertDialogBuilder

class SignInActivity : AppCompatActivity() {

    private lateinit var auth: FirebaseAuth
    private lateinit var authManager: AuthManager
    private lateinit var btnGoogle: MaterialButton
    private lateinit var btnGithub: MaterialButton
    private lateinit var etEmail: EditText
    private lateinit var etPassword: EditText
    private lateinit var btnSignIn: MaterialButton
    private lateinit var tvForgotPassword: TextView
    private lateinit var tvSignUp: TextView
    private var lastLoginInput: String = ""
    private var isCheckingExistingSession: Boolean = false

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_sign_in)

        auth = FirebaseAuth.getInstance()
        authManager = AuthManager(this)

        initViews()
        setupClickListeners()
    }

    override fun onStart() {
        super.onStart()
        checkExistingSession()
    }

    private fun checkExistingSession() {
        if (auth.currentUser == null || isCheckingExistingSession) {
            return
        }

        isCheckingExistingSession = true
        authManager.checkCurrentUserVerification { result ->
            isCheckingExistingSession = false
            when (result) {
                is AuthResult.Success -> navigateToMain()
                is AuthResult.VerificationRequired -> {
                    showVerificationRequiredDialog(result)
                }
                is AuthResult.Error -> {
                    authManager.signOut()
                    Toast.makeText(this, result.message ?: "Please sign in", Toast.LENGTH_SHORT).show()
                }
                AuthResult.Cancelled -> Unit
            }
        }
    }

    private fun navigateToMain() {
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }

    private fun initViews() {
        etEmail = findViewById(R.id.etEmail)
        etPassword = findViewById(R.id.etPassword)
        btnSignIn = findViewById(R.id.btnSignIn)
        tvForgotPassword = findViewById(R.id.tvForgotPassword)
        tvSignUp = findViewById(R.id.tvSignUp)
        btnGoogle = findViewById(R.id.btnGoogle)
        btnGithub = findViewById(R.id.btnGithub)
    }

    private fun setupClickListeners() {
        btnSignIn.setOnClickListener {
            val email = etEmail.text.toString().trim().lowercase()
            val password = etPassword.text.toString().trim()

            if (!validateInputs(email, password)) return@setOnClickListener

            lastLoginInput = email

            btnSignIn.isEnabled = false
            btnSignIn.text = "Signing In..."

            authManager.signInWithEmail(email, password) { result ->
                handleSignInResult(result)
            }
        }

        btnGoogle.setOnClickListener { handleGoogleLogin() }
        btnGithub.setOnClickListener { handleGithubLogin() }

        tvForgotPassword.setOnClickListener {
            showForgotPasswordBottomSheet()
        }

        tvSignUp.setOnClickListener {
            startActivity(Intent(this, SignUpActivity::class.java))
            finish()
        }
    }

    private fun handleSignInResult(result: AuthResult) {
        when (result) {
            is AuthResult.Success -> {
                UserProfilePrefs.cacheFromUser(
                    context = this,
                    user = auth.currentUser,
                    fallbackPhone = ""
                )
                Toast.makeText(this, "Welcome back!", Toast.LENGTH_SHORT).show()
                navigateToMain()
            }
            is AuthResult.Error -> {
                Toast.makeText(this, result.message ?: "Sign in failed", Toast.LENGTH_LONG).show()
                resetButton()
            }
            is AuthResult.VerificationRequired -> {
                showVerificationRequiredDialog(result)
                resetButton()
            }
            AuthResult.Cancelled -> {
                Toast.makeText(this, "Sign in cancelled", Toast.LENGTH_SHORT).show()
                resetButton()
            }
        }
    }

    private fun validateInputs(email: String, password: String): Boolean {
        if (email.isEmpty()) {
            etEmail.error = "Email is required"
            etEmail.requestFocus()
            return false
        }

        if (!Patterns.EMAIL_ADDRESS.matcher(email).matches()) {
            etEmail.error = "Enter valid email"
            etEmail.requestFocus()
            return false
        }

        if (password.isEmpty()) {
            etPassword.error = "Password is required"
            etPassword.requestFocus()
            return false
        }

        return true
    }

    private fun showForgotPasswordBottomSheet() {
        val bottomSheetDialog = BottomSheetDialog(this)
        val view = layoutInflater.inflate(R.layout.bottom_sheet_forgot_password, null)
        bottomSheetDialog.setContentView(view)

        val etForgotEmail = view.findViewById<EditText>(R.id.etForgotEmail)
        val btnSendReset = view.findViewById<MaterialButton>(R.id.btnSendReset)
        val tvCancel = view.findViewById<TextView>(R.id.tvCancel)

        val currentEmail = etEmail.text.toString().trim()
        if (currentEmail.isNotEmpty() && Patterns.EMAIL_ADDRESS.matcher(currentEmail).matches()) {
            etForgotEmail.setText(currentEmail)
            etForgotEmail.setSelection(currentEmail.length)
        }

        tvCancel.setOnClickListener {
            bottomSheetDialog.dismiss()
        }

        btnSendReset.setOnClickListener {
            val email = etForgotEmail.text.toString().trim().lowercase()

            if (email.isEmpty()) {
                etForgotEmail.error = "Email is required"
                return@setOnClickListener
            }

            if (!Patterns.EMAIL_ADDRESS.matcher(email).matches()) {
                etForgotEmail.error = "Enter valid email"
                return@setOnClickListener
            }

            btnSendReset.isEnabled = false
            btnSendReset.text = "Sending..."

            // Problem #4 Fix: Directly send reset email without deprecated check
            auth.sendPasswordResetEmail(email)
                .addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        Toast.makeText(
                            this,
                            "If an account exists with this email, a reset link has been sent.",
                            Toast.LENGTH_LONG
                        ).show()
                        bottomSheetDialog.dismiss()
                    } else {
                        val error = task.exception?.message ?: "Failed to send reset email"
                        Toast.makeText(this, error, Toast.LENGTH_LONG).show()
                        btnSendReset.isEnabled = true
                        btnSendReset.text = "Send Reset Link"
                    }
                }
        }

        bottomSheetDialog.show()
    }

    private fun handleGoogleLogin() {
        disableButtons()
        authManager.signInWithGoogle { result ->
            handleSignInResult(result)
        }
    }

    private fun handleGithubLogin() {
        disableButtons()
        authManager.signInWithGithub(this) { result ->
            handleSignInResult(result)
        }
    }

    private fun disableButtons() {
        btnSignIn.isEnabled = false
        btnGoogle.isEnabled = false
        btnGithub.isEnabled = false
        btnSignIn.text = "Please wait..."
    }

    private fun resetButton() {
        btnSignIn.isEnabled = true
        btnSignIn.text = "Sign In"
        btnGoogle.isEnabled = true
        btnGithub.isEnabled = true
    }

    private fun showVerificationRequiredDialog(result: AuthResult.VerificationRequired) {
        val details = buildString {
            append(result.message)
            append("\n\n")
            append("Email: ")
            append(if (result.emailVerified) "Verified" else "Not verified")
            append("\n")
            append("Phone: ")
            append(if (result.phoneVerified) "Verified" else "Not verified")
        }

        val dialog = MaterialAlertDialogBuilder(this)
            .setTitle("Verification required")
            .setMessage(details)
            .setPositiveButton(
                if (!result.phoneVerified) "Verify phone" else "OK"
            ) { _, _ ->
                if (!result.phoneVerified) {
                    val phone = result.phone
                    if (phone.isNullOrBlank()) {
                        Toast.makeText(this, "Phone number not found. Update it in sign up.", Toast.LENGTH_LONG).show()
                    } else {
                        openPhoneVerification(phone, PhoneVerificationActivity.MODE_LINK)
                    }
                }
            }
            .setNegativeButton("Sign out") { _, _ ->
                authManager.signOut()
            }

        if (!result.emailVerified && auth.currentUser != null) {
            dialog.setNeutralButton("Resend email") { _, _ ->
                authManager.sendEmailVerificationForCurrentUser { resendResult ->
                    when (resendResult) {
                        is AuthResult.Success -> Toast.makeText(
                            this,
                            "Verification email sent",
                            Toast.LENGTH_SHORT
                        ).show()
                        is AuthResult.Error -> Toast.makeText(
                            this,
                            resendResult.message ?: "Failed to send verification email",
                            Toast.LENGTH_LONG
                        ).show()
                        else -> Unit
                    }
                }
            }
        }

        dialog.show()
    }

    private fun openPhoneVerification(phone: String, mode: String) {
        val intent = Intent(this, PhoneVerificationActivity::class.java)
            .putExtra(PhoneVerificationActivity.EXTRA_PHONE, phone)
            .putExtra(PhoneVerificationActivity.EXTRA_MODE, mode)
        startActivity(intent)
    }
}

package com.kartik.aistudyassistant.ui.auth

import android.content.Intent
import android.os.Bundle
import android.util.Patterns
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import com.kartik.aistudyassistant.data.local.UserProfilePrefs
import com.kartik.aistudyassistant.data.repository.AuthManager
import com.kartik.aistudyassistant.R
import com.google.android.material.button.MaterialButton
import com.google.firebase.auth.FirebaseAuth
import com.kartik.aistudyassistant.data.model.AuthResult
import com.kartik.aistudyassistant.ui.home.MainActivity
import com.google.android.material.bottomsheet.BottomSheetDialog
import com.google.android.material.dialog.MaterialAlertDialogBuilder

class SignInActivity : AppCompatActivity() {

    private lateinit var auth: FirebaseAuth
    private lateinit var authManager: AuthManager
    private lateinit var btnGoogle: MaterialButton
    private lateinit var btnGithub: MaterialButton
    private lateinit var etEmail: EditText
    private lateinit var etPassword: EditText
    private lateinit var btnSignIn: MaterialButton
    private lateinit var tvForgotPassword: TextView
    private lateinit var tvSignUp: TextView
    private var isCheckingExistingSession: Boolean = false

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_sign_in)

        auth = FirebaseAuth.getInstance()
        authManager = AuthManager(this)

        initViews()
        setupClickListeners()
    }

    override fun onStart() {
        super.onStart()
        checkExistingSession()
    }

    private fun checkExistingSession() {
        if (auth.currentUser == null || isCheckingExistingSession) {
            return
        }

        isCheckingExistingSession = true
        authManager.checkCurrentUserVerification { result ->
            isCheckingExistingSession = false
            when (result) {
                is AuthResult.Success -> navigateToMain()
                is AuthResult.VerificationRequired -> {
                    showVerificationRequiredDialog(result)
                }
                is AuthResult.Error -> {
                    authManager.signOut()
                    Toast.makeText(this, result.message ?: "Please sign in", Toast.LENGTH_SHORT).show()
                }
                AuthResult.Cancelled -> Unit
            }
        }
    }

    private fun navigateToMain() {
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }

    private fun initViews() {
        etEmail = findViewById(R.id.etEmail)
        etPassword = findViewById(R.id.etPassword)
        btnSignIn = findViewById(R.id.btnSignIn)
        tvForgotPassword = findViewById(R.id.tvForgotPassword)
        tvSignUp = findViewById(R.id.tvSignUp)
        btnGoogle = findViewById(R.id.btnGoogle)
        btnGithub = findViewById(R.id.btnGithub)
    }

    private fun setupClickListeners() {
        btnSignIn.setOnClickListener {
            val email = etEmail.text.toString().trim().lowercase()
            val password = etPassword.text.toString().trim()

            if (!validateInputs(email, password)) return@setOnClickListener

            btnSignIn.isEnabled = false
            btnSignIn.text = getString(R.string.signin_signing_in)

            authManager.signInWithEmail(email, password) { result ->
                handleSignInResult(result)
            }
        }

        btnGoogle.setOnClickListener { handleGoogleLogin() }
        btnGithub.setOnClickListener { handleGithubLogin() }

        tvForgotPassword.setOnClickListener {
            showForgotPasswordBottomSheet()
        }

        tvSignUp.setOnClickListener {
            startActivity(Intent(this, SignUpActivity::class.java))
            finish()
        }
    }

    private fun handleSignInResult(result: AuthResult) {
        when (result) {
            is AuthResult.Success -> {
                UserProfilePrefs.cacheFromUser(
                    context = this,
                    user = auth.currentUser,
                    fallbackPhone = ""
                )
                Toast.makeText(this, "Welcome back!", Toast.LENGTH_SHORT).show()
                navigateToMain()
            }
            is AuthResult.Error -> {
                Toast.makeText(this, result.message ?: "Sign in failed", Toast.LENGTH_LONG).show()
                resetButton()
            }
            is AuthResult.VerificationRequired -> {
                showVerificationRequiredDialog(result)
                resetButton()
            }
            AuthResult.Cancelled -> {
                Toast.makeText(this, "Sign in cancelled", Toast.LENGTH_SHORT).show()
                resetButton()
            }
        }
    }

    private fun validateInputs(email: String, password: String): Boolean {
        if (email.isEmpty()) {
            etEmail.error = "Email is required"
            etEmail.requestFocus()
            return false
        }

        if (!Patterns.EMAIL_ADDRESS.matcher(email).matches()) {
            etEmail.error = "Enter valid email"
            etEmail.requestFocus()
            return false
        }

        if (password.isEmpty()) {
            etPassword.error = "Password is required"
            etPassword.requestFocus()
            return false
        }

        return true
    }

    private fun showForgotPasswordBottomSheet() {
        val bottomSheetDialog = BottomSheetDialog(this)
        val root = findViewById<android.view.ViewGroup>(android.R.id.content)
        val view = layoutInflater.inflate(R.layout.bottom_sheet_forgot_password, root, false)
        bottomSheetDialog.setContentView(view)

        val etForgotEmail = view.findViewById<EditText>(R.id.etForgotEmail)
        val btnSendReset = view.findViewById<MaterialButton>(R.id.btnSendReset)
        val tvCancel = view.findViewById<TextView>(R.id.tvCancel)

        val currentEmail = etEmail.text.toString().trim()
        if (currentEmail.isNotEmpty() && Patterns.EMAIL_ADDRESS.matcher(currentEmail).matches()) {
            etForgotEmail.setText(currentEmail)
            etForgotEmail.setSelection(currentEmail.length)
        }

        tvCancel.setOnClickListener {
            bottomSheetDialog.dismiss()
        }

        btnSendReset.setOnClickListener {
            val email = etForgotEmail.text.toString().trim().lowercase()

            if (email.isEmpty()) {
                etForgotEmail.error = "Email is required"
                return@setOnClickListener
            }

            if (!Patterns.EMAIL_ADDRESS.matcher(email).matches()) {
                etForgotEmail.error = "Enter valid email"
                return@setOnClickListener
            }

            btnSendReset.isEnabled = false
            btnSendReset.text = getString(R.string.common_sending)

            // Problem #4 Fix: Directly send reset email without deprecated check
            auth.sendPasswordResetEmail(email)
                .addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        Toast.makeText(
                            this,
                            "If an account exists with this email, a reset link has been sent.",
                            Toast.LENGTH_LONG
                        ).show()
                        bottomSheetDialog.dismiss()
                    } else {
                        val error = task.exception?.message ?: "Failed to send reset email"
                        Toast.makeText(this, error, Toast.LENGTH_LONG).show()
                        btnSendReset.isEnabled = true
                        btnSendReset.text = getString(R.string.signin_send_reset_link)
                    }
                }
        }

        bottomSheetDialog.show()
    }

    private fun handleGoogleLogin() {
        disableButtons()
        authManager.signInWithGoogle { result ->
            handleSignInResult(result)
        }
    }

    private fun handleGithubLogin() {
        disableButtons()
        authManager.signInWithGithub(this) { result ->
            handleSignInResult(result)
        }
    }

    private fun disableButtons() {
        btnSignIn.isEnabled = false
        btnGoogle.isEnabled = false
        btnGithub.isEnabled = false
        btnSignIn.text = getString(R.string.signin_please_wait)
    }

    private fun resetButton() {
        btnSignIn.isEnabled = true
        btnSignIn.text = getString(R.string.signin_sign_in)
        btnGoogle.isEnabled = true
        btnGithub.isEnabled = true
    }

    private fun showVerificationRequiredDialog(result: AuthResult.VerificationRequired) {
        val details = buildString {
            append(result.message)
            append("\n\n")
            append("Email: ")
            append(if (result.emailVerified) "Verified" else "Not verified")
            append("\n")
            append("Phone: ")
            append(if (result.phoneVerified) "Verified" else "Not verified")
        }

        val dialog = MaterialAlertDialogBuilder(this)
            .setTitle("Verification required")
            .setMessage(details)
            .setPositiveButton(
                if (!result.phoneVerified) "Verify phone" else "OK"
            ) { _, _ ->
                if (!result.phoneVerified) {
                    val phone = result.phone
                    if (phone.isNullOrBlank()) {
                        Toast.makeText(this, "Phone number not found. Update it in sign up.", Toast.LENGTH_LONG).show()
                    } else {
                        openPhoneVerification(phone)
                    }
                }
            }
            .setNegativeButton("Sign out") { _, _ ->
                authManager.signOut()
            }

        if (!result.emailVerified && auth.currentUser != null) {
            dialog.setNeutralButton("Resend email") { _, _ ->
                authManager.sendEmailVerificationForCurrentUser { resendResult ->
                    when (resendResult) {
                        is AuthResult.Success -> Toast.makeText(
                            this,
                            "Verification email sent",
                            Toast.LENGTH_SHORT
                        ).show()
                        is AuthResult.Error -> Toast.makeText(
                            this,
                            resendResult.message ?: "Failed to send verification email",
                            Toast.LENGTH_LONG
                        ).show()
                        else -> Unit
                    }
                }
            }
        }

        dialog.show()
    }

    private fun openPhoneVerification(phone: String) {
        val intent = Intent(this, PhoneVerificationActivity::class.java)
            .putExtra(PhoneVerificationActivity.EXTRA_PHONE, phone)
            .putExtra(PhoneVerificationActivity.EXTRA_MODE, PhoneVerificationActivity.MODE_LINK)
        startActivity(intent)
    }
}

package com.kartik.aistudyassistant.ui.auth

import android.content.Context
import android.content.Intent
import android.os.CountDownTimer
import android.net.ConnectivityManager
import android.net.NetworkCapabilities
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.util.Patterns
import android.view.View
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import com.kartik.aistudyassistant.R
import com.kartik.aistudyassistant.data.local.UserProfilePrefs
import com.google.android.material.button.MaterialButton
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.auth.PhoneAuthProvider
import com.kartik.aistudyassistant.data.repository.AuthManager
import com.kartik.aistudyassistant.data.model.AuthResult
import com.kartik.aistudyassistant.ui.home.MainActivity
import com.google.android.material.dialog.MaterialAlertDialogBuilder

class SignUpActivity : AppCompatActivity() {

    companion object {
        private const val PHONE_OTP_BLOCK_COOLDOWN_MILLIS = 10 * 60 * 1000L
    }

    private lateinit var auth: FirebaseAuth
    private lateinit var authManager: AuthManager

    // Views
    private lateinit var etEmail: EditText
    private lateinit var etPhone: EditText
    private lateinit var etPassword: EditText
    private lateinit var etConfirmPassword: EditText
    private lateinit var etPhoneOtp: EditText
    private lateinit var btnSignUp: MaterialButton
    private lateinit var btnGoogle: MaterialButton
    private lateinit var btnGithub: MaterialButton
    private lateinit var btnSendEmailOtp: MaterialButton
    private lateinit var btnCheckEmailVerified: MaterialButton
    private lateinit var btnSendPhoneOtp: MaterialButton
    private lateinit var btnResendPhoneOtp: MaterialButton
    private lateinit var btnVerifyPhoneOtp: MaterialButton
    private var btnEditVerifiedContacts: MaterialButton? = null
    private lateinit var tvEmailVerificationStatus: TextView
    private lateinit var tvPhoneVerificationStatus: TextView
    private var tvVerifiedContactsLockedHint: TextView? = null
    private var tvPhoneOtpBlockedCountdown: TextView? = null

    private var emailVerified = false
    private var phoneVerified = false
    private var verificationId: String? = null
    private var resendToken: PhoneAuthProvider.ForceResendingToken? = null
    private var lastVerifiedEmail: String? = null
    private var lastOtpTargetPhone: String? = null
    private var phoneOtpBlockTimer: CountDownTimer? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_sign_up)

        auth = FirebaseAuth.getInstance()
        authManager = AuthManager(this)

        initViews()
        setupClickListeners()
    }

    private fun initViews() {
        etEmail = findViewById(R.id.etEmail)
        etPhone = findViewById(R.id.etPhone)
        etPassword = findViewById(R.id.etCreatePassword)
        etConfirmPassword = findViewById(R.id.etConfirmPassword)
        etPhoneOtp = findViewById(R.id.etPhoneOtp)
        btnSignUp = findViewById(R.id.btnSignUp)
        btnGoogle = findViewById(R.id.btnGoogle)
        btnGithub = findViewById(R.id.btnGithub)
        btnSendEmailOtp = findViewById(R.id.btnSendEmailOtp)
        btnCheckEmailVerified = findViewById(R.id.btnCheckEmailVerified)
        btnSendPhoneOtp = findViewById(R.id.btnSendPhoneOtp)
        btnResendPhoneOtp = findViewById(R.id.btnResendPhoneOtp)
        btnVerifyPhoneOtp = findViewById(R.id.btnVerifyPhoneOtp)
        btnEditVerifiedContacts = findViewById(R.id.btnEditVerifiedContacts)
        tvEmailVerificationStatus = findViewById(R.id.tvEmailVerificationStatus)
        tvPhoneVerificationStatus = findViewById(R.id.tvPhoneVerificationStatus)
        tvVerifiedContactsLockedHint = findViewById(R.id.tvVerifiedContactsLockedHint)
        tvPhoneOtpBlockedCountdown = findViewById(R.id.tvPhoneOtpBlockedCountdown)

        updateVerificationUi()

        val tvSignIn = findViewById<TextView>(R.id.tvSignIn)

        tvSignIn.setOnClickListener {
            startActivity(Intent(this, SignInActivity::class.java))
            finish()
        }

        etPhone.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit

            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                val normalizedCurrent = s?.toString()?.trim().orEmpty()
                val wasBoundToOtp = !lastOtpTargetPhone.isNullOrBlank()
                if (wasBoundToOtp && normalizedCurrent != lastOtpTargetPhone) {
                    resetPhoneVerificationState()
                }
            }

            override fun afterTextChanged(s: Editable?) = Unit
        })

        etEmail.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit

            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                val currentEmail = s?.toString()?.trim()?.lowercase().orEmpty()
                val verifiedEmail = lastVerifiedEmail
                if (!verifiedEmail.isNullOrBlank() && currentEmail != verifiedEmail) {
                    resetEmailVerificationState(clearPhoneState = true)
                }
            }

            override fun afterTextChanged(s: Editable?) = Unit
        })
    }

    private fun setupClickListeners() {
        btnSignUp.setOnClickListener {
            if (!isNetworkAvailable()) {
                Toast.makeText(this, "No internet connection", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            val phone = etPhone.text.toString().trim()
            val email = etEmail.text.toString().trim().lowercase()
            val password = etPassword.text.toString().trim()
            val confirmPassword = etConfirmPassword.text.toString().trim()

            if (emailVerified && lastVerifiedEmail != null && email != lastVerifiedEmail) {
                resetEmailVerificationState(clearPhoneState = true)
                Toast.makeText(this, "Email changed. Verify email again before creating account", Toast.LENGTH_LONG).show()
                return@setOnClickListener
            }

            if (phoneVerified && lastOtpTargetPhone != null && phone != lastOtpTargetPhone) {
                resetPhoneVerificationState()
                Toast.makeText(this, "Phone changed. Verify phone again before creating account", Toast.LENGTH_LONG).show()
                return@setOnClickListener
            }

            if (!emailVerified || !phoneVerified) {
                Toast.makeText(this, "Verify email and phone before creating account", Toast.LENGTH_LONG).show()
                return@setOnClickListener
            }

            if (!validatePasswordInputs(password, confirmPassword)) {
                return@setOnClickListener
            }

            btnSignUp.isEnabled = false
            btnSignUp.text = "Creating Account..."

            authManager.completeVerifiedEmailSignUp(phone, password) { result ->
                handleSignUpResult(result)
            }
        }

        btnSendEmailOtp.setOnClickListener {
            val email = etEmail.text.toString().trim().lowercase()
            if (!Patterns.EMAIL_ADDRESS.matcher(email).matches()) {
                etEmail.error = "Enter valid email"
                etEmail.requestFocus()
                return@setOnClickListener
            }

            resetEmailVerificationState(clearPhoneState = true)

            btnSendEmailOtp.isEnabled = false
            btnSendEmailOtp.text = "Sending..."
            authManager.startPendingEmailVerification(email) { result ->
                btnSendEmailOtp.isEnabled = true
                btnSendEmailOtp.text = "Send Verification Email"
                when (result) {
                    is AuthResult.Success -> {
                        lastVerifiedEmail = email
                        setEmailStatus(false, "Verification email sent. Check inbox and tap Check Verified.", false)
                        Toast.makeText(this, "Verification email sent", Toast.LENGTH_SHORT).show()
                    }
                    is AuthResult.Error -> {
                        Toast.makeText(this, result.message ?: "Failed to send email verification", Toast.LENGTH_LONG).show()
                    }
                    else -> Unit
                }
            }
        }

        btnCheckEmailVerified.setOnClickListener {
            btnCheckEmailVerified.isEnabled = false
            btnCheckEmailVerified.text = "Checking..."
            authManager.refreshEmailVerificationStatus { verified, error ->
                btnCheckEmailVerified.isEnabled = true
                btnCheckEmailVerified.text = "Check Verified"
                if (error != null) {
                    Toast.makeText(this, error, Toast.LENGTH_LONG).show()
                    return@refreshEmailVerificationStatus
                }

                emailVerified = verified
                if (verified) {
                    lastVerifiedEmail = etEmail.text.toString().trim().lowercase()
                }
                setEmailStatus(
                    verified,
                    if (verified) "Email verified" else "Email not verified",
                    verified
                )
                updateVerificationUi()
            }
        }

        btnSendPhoneOtp.setOnClickListener {
            if (!emailVerified) {
                Toast.makeText(this, "Verify email first", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            val phone = etPhone.text.toString().trim()
            if (!isValidIndianPhone(phone)) {
                etPhone.error = "Enter valid 10-digit Indian phone number"
                etPhone.requestFocus()
                return@setOnClickListener
            }

            sendPhoneOtp(phone)
        }

        btnResendPhoneOtp.setOnClickListener {
            val token = resendToken
            val phone = etPhone.text.toString().trim()
            if (token == null) {
                sendPhoneOtp(phone)
                return@setOnClickListener
            }

            btnResendPhoneOtp.isEnabled = false
            btnResendPhoneOtp.text = "Resending..."
            authManager.resendPhoneVerification(
                activity = this,
                rawPhone = phone,
                token = token,
                onCodeSent = { newVerificationId, newToken ->
                    verificationId = newVerificationId
                    resendToken = newToken
                    clearPhoneOtpBlockCounter()
                    btnResendPhoneOtp.isEnabled = true
                    btnResendPhoneOtp.text = "Resend OTP"
                    Toast.makeText(this, "OTP resent", Toast.LENGTH_SHORT).show()
                },
                onVerified = { result ->
                    btnResendPhoneOtp.isEnabled = true
                    btnResendPhoneOtp.text = "Resend OTP"
                    handlePhoneVerificationResult(result)
                },
                onError = { message ->
                    handlePhoneOtpBlockedErrorIfNeeded(message)
                    btnResendPhoneOtp.isEnabled = true
                    btnResendPhoneOtp.text = "Resend OTP"
                    Toast.makeText(this, message, Toast.LENGTH_LONG).show()
                }
            )
        }

        btnVerifyPhoneOtp.setOnClickListener {
            val currentVerificationId = verificationId
            if (currentVerificationId.isNullOrBlank()) {
                Toast.makeText(this, "Send OTP first", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            val otp = etPhoneOtp.text.toString().trim()
            if (otp.length != 6 || !otp.all { it.isDigit() }) {
                etPhoneOtp.error = "Enter valid 6-digit OTP"
                etPhoneOtp.requestFocus()
                return@setOnClickListener
            }

            btnVerifyPhoneOtp.isEnabled = false
            btnVerifyPhoneOtp.text = "Verifying..."
            authManager.verifyPhoneCode(currentVerificationId, otp) { result ->
                btnVerifyPhoneOtp.isEnabled = true
                btnVerifyPhoneOtp.text = "Verify Phone OTP"
                handlePhoneVerificationResult(result)
            }
        }

        btnGoogle.setOnClickListener {
            disableSocialButtons()
            authManager.signInWithGoogle { result ->
                handleSignUpResult(result)
            }
        }

        btnEditVerifiedContacts?.setOnClickListener {
            resetEmailVerificationState(clearPhoneState = true)
            Toast.makeText(this, "Email and phone unlocked. Verify again to continue", Toast.LENGTH_SHORT).show()
        }

        btnGithub.setOnClickListener {
            disableSocialButtons()
            authManager.signInWithGithub(this) { result ->
                handleSignUpResult(result)
            }
        }
    }

    private fun handleSignUpResult(result: AuthResult) {
        when (result) {
            is AuthResult.Success -> {
                UserProfilePrefs.cacheFromUser(
                    context = this,
                    user = auth.currentUser,
                    fallbackPhone = etPhone.text?.toString()?.trim().orEmpty()
                )
                val message = if (result.isNewUser) {
                    "Account created successfully!"
                } else {
                    "Welcome back!"
                }
                Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
                startActivity(Intent(this, MainActivity::class.java))
                finish()
            }
            is AuthResult.VerificationRequired -> {
                showVerificationRequiredDialog(result)
                enableAllButtons()
            }
            is AuthResult.Error -> {
                Toast.makeText(this, result.message ?: "Sign up failed", Toast.LENGTH_LONG).show()
                enableAllButtons()
            }
            AuthResult.Cancelled -> {
                Toast.makeText(this, "Sign up cancelled", Toast.LENGTH_SHORT).show()
                enableAllButtons()
            }
        }
    }

    private fun validatePasswordInputs(password: String, confirmPassword: String): Boolean {
        if (password.isEmpty() || confirmPassword.isEmpty()) {
            Toast.makeText(this, "Password fields are required", Toast.LENGTH_SHORT).show()
            return false
        }

        if (password.length < 6) {
            etPassword.error = "Password must be at least 6 characters"
            etPassword.requestFocus()
            return false
        }

        if (password != confirmPassword) {
            etConfirmPassword.error = "Passwords do not match"
            etConfirmPassword.requestFocus()
            return false
        }

        return true
    }

    private fun disableSocialButtons() {
        btnSignUp.isEnabled = false
        btnGoogle.isEnabled = false
        btnGithub.isEnabled = false
        btnGoogle.alpha = 0.5f
        btnGithub.alpha = 0.5f
    }

    private fun enableAllButtons() {
        btnSignUp.text = "Create Account"
        btnGoogle.isEnabled = true
        btnGithub.isEnabled = true
        btnGoogle.alpha = 1f
        btnGithub.alpha = 1f
        updateVerificationUi()
    }

    private fun isNetworkAvailable(): Boolean {
        val connectivityManager = getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager
        val activeNetwork = connectivityManager.activeNetwork
        val networkCapabilities = connectivityManager.getNetworkCapabilities(activeNetwork)
        return networkCapabilities != null &&
                (networkCapabilities.hasTransport(NetworkCapabilities.TRANSPORT_WIFI) ||
                        networkCapabilities.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR) ||
                        networkCapabilities.hasTransport(NetworkCapabilities.TRANSPORT_ETHERNET))
    }

    private fun sendPhoneOtp(phone: String) {
        btnSendPhoneOtp.isEnabled = false
        btnSendPhoneOtp.text = "Sending..."
        authManager.startPhoneVerification(
            activity = this,
            rawPhone = phone,
            onCodeSent = { sentVerificationId, token ->
                verificationId = sentVerificationId
                resendToken = token
                lastOtpTargetPhone = phone.trim()
                clearPhoneOtpBlockCounter()
                btnSendPhoneOtp.isEnabled = true
                btnSendPhoneOtp.text = "Send Phone OTP"
                btnResendPhoneOtp.isEnabled = true
                setPhoneStatus(false, "OTP sent. Enter code to verify phone.", false)
            },
            onVerified = { result ->
                btnSendPhoneOtp.isEnabled = true
                btnSendPhoneOtp.text = "Send Phone OTP"
                handlePhoneVerificationResult(result)
            },
            onError = { message ->
                handlePhoneOtpBlockedErrorIfNeeded(message)
                btnSendPhoneOtp.isEnabled = true
                btnSendPhoneOtp.text = "Send Phone OTP"
                Toast.makeText(this, message, Toast.LENGTH_LONG).show()
            }
        )
    }

    private fun handlePhoneVerificationResult(result: AuthResult) {
        when (result) {
            is AuthResult.Success -> {
                clearPhoneOtpBlockCounter()
                phoneVerified = true
                lastOtpTargetPhone = etPhone.text?.toString()?.trim().orEmpty()
                setPhoneStatus(true, "Phone verified", true)
                updateVerificationUi()
            }
            is AuthResult.VerificationRequired -> {
                if (result.phoneVerified) {
                    clearPhoneOtpBlockCounter()
                }
                phoneVerified = result.phoneVerified
                if (result.phoneVerified) {
                    lastOtpTargetPhone = etPhone.text?.toString()?.trim().orEmpty()
                }
                setPhoneStatus(
                    result.phoneVerified,
                    if (result.phoneVerified) "Phone verified" else "Phone not verified",
                    result.phoneVerified
                )
                updateVerificationUi()
            }
            is AuthResult.Error -> {
                Toast.makeText(this, result.message ?: "Phone verification failed", Toast.LENGTH_LONG).show()
                setPhoneStatus(false, "Phone not verified", false)
            }
            AuthResult.Cancelled -> Unit
        }
    }

    private fun updateVerificationUi() {
        val isFullyVerified = emailVerified && phoneVerified

        etEmail.isEnabled = !isFullyVerified
        etPhone.isEnabled = !isFullyVerified

        btnSendEmailOtp.isEnabled = !isFullyVerified
        btnCheckEmailVerified.isEnabled = !isFullyVerified
        btnSendPhoneOtp.isEnabled = emailVerified && !isFullyVerified
        btnResendPhoneOtp.isEnabled = resendToken != null && !phoneVerified && !isFullyVerified
        btnVerifyPhoneOtp.isEnabled = !phoneVerified && !isFullyVerified
        btnEditVerifiedContacts?.visibility = if (isFullyVerified) View.VISIBLE else View.GONE
        tvVerifiedContactsLockedHint?.visibility = if (isFullyVerified) View.VISIBLE else View.GONE
        btnSignUp.isEnabled = isFullyVerified
    }

    private fun resetEmailVerificationState(clearPhoneState: Boolean) {
        emailVerified = false
        lastVerifiedEmail = null
        setEmailStatus(false, "Email not verified", false)
        if (clearPhoneState) {
            resetPhoneVerificationState()
        } else {
            updateVerificationUi()
        }
    }

    private fun resetPhoneVerificationState() {
        phoneVerified = false
        verificationId = null
        resendToken = null
        lastOtpTargetPhone = null
        etPhoneOtp.text?.clear()
        clearPhoneOtpBlockCounter()
        setPhoneStatus(false, "Phone not verified", false)
        updateVerificationUi()
    }

    private fun handlePhoneOtpBlockedErrorIfNeeded(message: String) {
        if (isOtpBlockedError(message)) {
            startPhoneOtpBlockCounter()
        }
    }

    private fun isOtpBlockedError(message: String): Boolean {
        val normalized = message.lowercase()
        return normalized.contains("blocked") && normalized.contains("unusual activity")
    }

    private fun startPhoneOtpBlockCounter() {
        phoneOtpBlockTimer?.cancel()
        tvPhoneOtpBlockedCountdown?.visibility = View.VISIBLE

        phoneOtpBlockTimer = object : CountDownTimer(PHONE_OTP_BLOCK_COOLDOWN_MILLIS, 1000L) {
            override fun onTick(millisUntilFinished: Long) {
                val totalSeconds = millisUntilFinished / 1000
                val minutes = totalSeconds / 60
                val seconds = totalSeconds % 60
                tvPhoneOtpBlockedCountdown?.text =
                    "Phone OTP temporarily blocked. Try again in %02d:%02d".format(minutes, seconds)
            }

            override fun onFinish() {
                tvPhoneOtpBlockedCountdown?.visibility = View.GONE
                tvPhoneOtpBlockedCountdown?.text = ""
                phoneOtpBlockTimer = null
            }
        }.start()
    }

    private fun clearPhoneOtpBlockCounter() {
        phoneOtpBlockTimer?.cancel()
        phoneOtpBlockTimer = null
        tvPhoneOtpBlockedCountdown?.visibility = View.GONE
        tvPhoneOtpBlockedCountdown?.text = ""
    }

    override fun onDestroy() {
        clearPhoneOtpBlockCounter()
        super.onDestroy()
    }

    private fun setEmailStatus(verified: Boolean, text: String, successTone: Boolean) {
        tvEmailVerificationStatus.text = text
        val color = if (verified || successTone) R.color.accent_green else R.color.red
        tvEmailVerificationStatus.setTextColor(ContextCompat.getColor(this, color))
    }

    private fun setPhoneStatus(verified: Boolean, text: String, successTone: Boolean) {
        tvPhoneVerificationStatus.text = text
        val color = if (verified || successTone) R.color.accent_green else R.color.red
        tvPhoneVerificationStatus.setTextColor(ContextCompat.getColor(this, color))
    }

    private fun isValidIndianPhone(phone: String): Boolean {
        return phone.length == 10 && phone.all { it.isDigit() }
    }

    private fun showVerificationRequiredDialog(result: AuthResult.VerificationRequired) {
        val details = buildString {
            append(result.message)
            append("\n\n")
            append("Email: ")
            append(if (result.emailVerified) "Verified" else "Not verified")
            append("\n")
            append("Phone: ")
            append(if (result.phoneVerified) "Verified" else "Not verified")
        }

        val dialog = MaterialAlertDialogBuilder(this)
            .setTitle("Verify your account")
            .setMessage(details)
            .setPositiveButton(
                if (!result.phoneVerified) "Verify phone" else "Go to Sign In"
            ) { _, _ ->
                if (!result.phoneVerified) {
                    val phone = result.phone ?: etPhone.text?.toString()?.trim().orEmpty()
                    if (phone.isBlank()) {
                        Toast.makeText(this, "Phone number is required for OTP verification", Toast.LENGTH_LONG).show()
                    } else {
                        openPhoneVerification(phone)
                    }
                } else {
                    startActivity(Intent(this, SignInActivity::class.java))
                    finish()
                }
            }
            .setNegativeButton("Sign out") { _, _ ->
                authManager.signOut()
            }

        if (!result.emailVerified && auth.currentUser != null) {
            dialog.setNeutralButton("Resend email") { _, _ ->
                authManager.sendEmailVerificationForCurrentUser { resendResult ->
                    when (resendResult) {
                        is AuthResult.Success -> Toast.makeText(
                            this,
                            "Verification email sent",
                            Toast.LENGTH_SHORT
                        ).show()
                        is AuthResult.Error -> Toast.makeText(
                            this,
                            resendResult.message ?: "Failed to send verification email",
                            Toast.LENGTH_LONG
                        ).show()
                        else -> Unit
                    }
                }
            }
        }

        dialog.show()
    }

    private fun openPhoneVerification(phone: String) {
        val intent = Intent(this, PhoneVerificationActivity::class.java)
            .putExtra(PhoneVerificationActivity.EXTRA_PHONE, phone)
            .putExtra(PhoneVerificationActivity.EXTRA_MODE, PhoneVerificationActivity.MODE_LINK)
        startActivity(intent)
    }
}

package com.kartik.aistudyassistant.ui.auth

import android.content.Context
import android.content.Intent
import android.os.CountDownTimer
import android.net.ConnectivityManager
import android.net.NetworkCapabilities
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.util.Patterns
import android.view.View
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import com.kartik.aistudyassistant.R
import com.kartik.aistudyassistant.data.local.UserProfilePrefs
import com.google.android.material.button.MaterialButton
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.auth.PhoneAuthProvider
import com.kartik.aistudyassistant.data.repository.AuthManager
import com.kartik.aistudyassistant.data.model.AuthResult
import com.kartik.aistudyassistant.ui.home.MainActivity
import com.google.android.material.dialog.MaterialAlertDialogBuilder

class SignUpActivity : AppCompatActivity() {

    companion object {
        private const val PHONE_OTP_BLOCK_COOLDOWN_MILLIS = 10 * 60 * 1000L
    }

    private lateinit var auth: FirebaseAuth
    private lateinit var authManager: AuthManager

    // Views
    private lateinit var etEmail: EditText
    private lateinit var etPhone: EditText
    private lateinit var etPassword: EditText
    private lateinit var etConfirmPassword: EditText
    private lateinit var etPhoneOtp: EditText
    private lateinit var btnSignUp: MaterialButton
    private lateinit var btnGoogle: MaterialButton
    private lateinit var btnGithub: MaterialButton
    private lateinit var btnSendEmailOtp: MaterialButton
    private lateinit var btnCheckEmailVerified: MaterialButton
    private lateinit var btnSendPhoneOtp: MaterialButton
    private lateinit var btnResendPhoneOtp: MaterialButton
    private lateinit var btnVerifyPhoneOtp: MaterialButton
    private var btnEditVerifiedContacts: MaterialButton? = null
    private lateinit var tvEmailVerificationStatus: TextView
    private lateinit var tvPhoneVerificationStatus: TextView
    private var tvVerifiedContactsLockedHint: TextView? = null
    private var tvPhoneOtpBlockedCountdown: TextView? = null

    private var emailVerified = false
    private var phoneVerified = false
    private var verificationId: String? = null
    private var resendToken: PhoneAuthProvider.ForceResendingToken? = null
    private var lastVerifiedEmail: String? = null
    private var lastOtpTargetPhone: String? = null
    private var phoneOtpBlockTimer: CountDownTimer? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_sign_up)

        auth = FirebaseAuth.getInstance()
        authManager = AuthManager(this)

        initViews()
        setupClickListeners()
    }

    private fun initViews() {
        etEmail = findViewById(R.id.etEmail)
        etPhone = findViewById(R.id.etPhone)
        etPassword = findViewById(R.id.etCreatePassword)
        etConfirmPassword = findViewById(R.id.etConfirmPassword)
        etPhoneOtp = findViewById(R.id.etPhoneOtp)
        btnSignUp = findViewById(R.id.btnSignUp)
        btnGoogle = findViewById(R.id.btnGoogle)
        btnGithub = findViewById(R.id.btnGithub)
        btnSendEmailOtp = findViewById(R.id.btnSendEmailOtp)
        btnCheckEmailVerified = findViewById(R.id.btnCheckEmailVerified)
        btnSendPhoneOtp = findViewById(R.id.btnSendPhoneOtp)
        btnResendPhoneOtp = findViewById(R.id.btnResendPhoneOtp)
        btnVerifyPhoneOtp = findViewById(R.id.btnVerifyPhoneOtp)
        btnEditVerifiedContacts = findViewById(R.id.btnEditVerifiedContacts)
        tvEmailVerificationStatus = findViewById(R.id.tvEmailVerificationStatus)
        tvPhoneVerificationStatus = findViewById(R.id.tvPhoneVerificationStatus)
        tvVerifiedContactsLockedHint = findViewById(R.id.tvVerifiedContactsLockedHint)
        tvPhoneOtpBlockedCountdown = findViewById(R.id.tvPhoneOtpBlockedCountdown)

        updateVerificationUi()

        val tvSignIn = findViewById<TextView>(R.id.tvSignIn)

        tvSignIn.setOnClickListener {
            startActivity(Intent(this, SignInActivity::class.java))
            finish()
        }

        etPhone.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit

            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                val normalizedCurrent = s?.toString()?.trim().orEmpty()
                val wasBoundToOtp = !lastOtpTargetPhone.isNullOrBlank()
                if (wasBoundToOtp && normalizedCurrent != lastOtpTargetPhone) {
                    resetPhoneVerificationState()
                }
            }

            override fun afterTextChanged(s: Editable?) = Unit
        })

        etEmail.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit

            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                val currentEmail = s?.toString()?.trim()?.lowercase().orEmpty()
                val verifiedEmail = lastVerifiedEmail
                if (!verifiedEmail.isNullOrBlank() && currentEmail != verifiedEmail) {
                    resetEmailVerificationState()
                }
            }

            override fun afterTextChanged(s: Editable?) = Unit
        })
    }

    private fun setupClickListeners() {
        btnSignUp.setOnClickListener {
            if (!isNetworkAvailable()) {
                Toast.makeText(this, "No internet connection", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            val phone = etPhone.text.toString().trim()
            val email = etEmail.text.toString().trim().lowercase()
            val password = etPassword.text.toString().trim()
            val confirmPassword = etConfirmPassword.text.toString().trim()

            if (emailVerified && lastVerifiedEmail != null && email != lastVerifiedEmail) {
                resetEmailVerificationState()
                Toast.makeText(this, "Email changed. Verify email again before creating account", Toast.LENGTH_LONG).show()
                return@setOnClickListener
            }

            if (phoneVerified && lastOtpTargetPhone != null && phone != lastOtpTargetPhone) {
                resetPhoneVerificationState()
                Toast.makeText(this, "Phone changed. Verify phone again before creating account", Toast.LENGTH_LONG).show()
                return@setOnClickListener
            }

            if (!emailVerified || !phoneVerified) {
                Toast.makeText(this, "Verify email and phone before creating account", Toast.LENGTH_LONG).show()
                return@setOnClickListener
            }

            if (!validatePasswordInputs(password, confirmPassword)) {
                return@setOnClickListener
            }

            btnSignUp.isEnabled = false
            btnSignUp.text = getString(R.string.signup_creating_account)

            authManager.completeVerifiedEmailSignUp(phone, password) { result ->
                handleSignUpResult(result)
            }
        }

        btnSendEmailOtp.setOnClickListener {
            val email = etEmail.text.toString().trim().lowercase()
            if (!Patterns.EMAIL_ADDRESS.matcher(email).matches()) {
                etEmail.error = "Enter valid email"
                etEmail.requestFocus()
                return@setOnClickListener
            }

            resetEmailVerificationState()

            btnSendEmailOtp.isEnabled = false
            btnSendEmailOtp.text = getString(R.string.common_sending)
            authManager.startPendingEmailVerification(email) { result ->
                btnSendEmailOtp.isEnabled = true
                btnSendEmailOtp.text = getString(R.string.signup_send_verification_email)
                when (result) {
                    is AuthResult.Success -> {
                        lastVerifiedEmail = email
                        setEmailStatus(false, "Verification email sent. Check inbox and tap Check Verified.", false)
                        Toast.makeText(this, "Verification email sent", Toast.LENGTH_SHORT).show()
                    }
                    is AuthResult.Error -> {
                        Toast.makeText(this, result.message ?: "Failed to send email verification", Toast.LENGTH_LONG).show()
                    }
                    else -> Unit
                }
            }
        }

        btnCheckEmailVerified.setOnClickListener {
            btnCheckEmailVerified.isEnabled = false
            btnCheckEmailVerified.text = getString(R.string.signup_checking)
            authManager.refreshEmailVerificationStatus { verified, error ->
                btnCheckEmailVerified.isEnabled = true
                btnCheckEmailVerified.text = getString(R.string.signup_check_verified)
                if (error != null) {
                    Toast.makeText(this, error, Toast.LENGTH_LONG).show()
                    return@refreshEmailVerificationStatus
                }

                emailVerified = verified
                if (verified) {
                    lastVerifiedEmail = etEmail.text.toString().trim().lowercase()
                }
                setEmailStatus(
                    verified,
                    if (verified) "Email verified" else "Email not verified",
                    verified
                )
                updateVerificationUi()
            }
        }

        btnSendPhoneOtp.setOnClickListener {
            if (!emailVerified) {
                Toast.makeText(this, "Verify email first", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            val phone = etPhone.text.toString().trim()
            if (!isValidIndianPhone(phone)) {
                etPhone.error = "Enter valid 10-digit Indian phone number"
                etPhone.requestFocus()
                return@setOnClickListener
            }

            sendPhoneOtp(phone)
        }

        btnResendPhoneOtp.setOnClickListener {
            val token = resendToken
            val phone = etPhone.text.toString().trim()
            if (token == null) {
                sendPhoneOtp(phone)
                return@setOnClickListener
            }

            btnResendPhoneOtp.isEnabled = false
            btnResendPhoneOtp.text = getString(R.string.signup_resending)
            authManager.resendPhoneVerification(
                activity = this,
                rawPhone = phone,
                token = token,
                onCodeSent = { newVerificationId, newToken ->
                    verificationId = newVerificationId
                    resendToken = newToken
                    clearPhoneOtpBlockCounter()
                    btnResendPhoneOtp.isEnabled = true
                    btnResendPhoneOtp.text = getString(R.string.signup_resend_otp)
                    Toast.makeText(this, getString(R.string.signup_otp_resent), Toast.LENGTH_SHORT).show()
                },
                onVerified = { result ->
                    btnResendPhoneOtp.isEnabled = true
                    btnResendPhoneOtp.text = getString(R.string.signup_resend_otp)
                    handlePhoneVerificationResult(result)
                },
                onError = { message ->
                    handlePhoneOtpBlockedErrorIfNeeded(message)
                    btnResendPhoneOtp.isEnabled = true
                    btnResendPhoneOtp.text = getString(R.string.signup_resend_otp)
                    Toast.makeText(this, message, Toast.LENGTH_LONG).show()
                }
            )
        }

        btnVerifyPhoneOtp.setOnClickListener {
            val currentVerificationId = verificationId
            if (currentVerificationId.isNullOrBlank()) {
                Toast.makeText(this, getString(R.string.signup_send_otp_first), Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            val otp = etPhoneOtp.text.toString().trim()
            if (otp.length != 6 || !otp.all { it.isDigit() }) {
                etPhoneOtp.error = "Enter valid 6-digit OTP"
                etPhoneOtp.requestFocus()
                return@setOnClickListener
            }

            btnVerifyPhoneOtp.isEnabled = false
            btnVerifyPhoneOtp.text = getString(R.string.signup_verifying)
            authManager.verifyPhoneCode(currentVerificationId, otp) { result ->
                btnVerifyPhoneOtp.isEnabled = true
                btnVerifyPhoneOtp.text = getString(R.string.signup_verify_phone_otp)
                handlePhoneVerificationResult(result)
            }
        }

        btnGoogle.setOnClickListener {
            disableSocialButtons()
            authManager.signInWithGoogle { result ->
                handleSignUpResult(result)
            }
        }

        btnEditVerifiedContacts?.setOnClickListener {
            resetEmailVerificationState()
            Toast.makeText(this, "Email and phone unlocked. Verify again to continue", Toast.LENGTH_SHORT).show()
        }

        btnGithub.setOnClickListener {
            disableSocialButtons()
            authManager.signInWithGithub(this) { result ->
                handleSignUpResult(result)
            }
        }
    }

    private fun handleSignUpResult(result: AuthResult) {
        when (result) {
            is AuthResult.Success -> {
                UserProfilePrefs.cacheFromUser(
                    context = this,
                    user = auth.currentUser,
                    fallbackPhone = etPhone.text?.toString()?.trim().orEmpty()
                )
                val message = if (result.isNewUser) {
                    "Account created successfully!"
                } else {
                    "Welcome back!"
                }
                Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
                startActivity(Intent(this, MainActivity::class.java))
                finish()
            }
            is AuthResult.VerificationRequired -> {
                showVerificationRequiredDialog(result)
                enableAllButtons()
            }
            is AuthResult.Error -> {
                Toast.makeText(this, result.message ?: "Sign up failed", Toast.LENGTH_LONG).show()
                enableAllButtons()
            }
            AuthResult.Cancelled -> {
                Toast.makeText(this, "Sign up cancelled", Toast.LENGTH_SHORT).show()
                enableAllButtons()
            }
        }
    }

    private fun validatePasswordInputs(password: String, confirmPassword: String): Boolean {
        if (password.isEmpty() || confirmPassword.isEmpty()) {
            Toast.makeText(this, "Password fields are required", Toast.LENGTH_SHORT).show()
            return false
        }

        if (password.length < 6) {
            etPassword.error = "Password must be at least 6 characters"
            etPassword.requestFocus()
            return false
        }

        if (password != confirmPassword) {
            etConfirmPassword.error = "Passwords do not match"
            etConfirmPassword.requestFocus()
            return false
        }

        return true
    }

    private fun disableSocialButtons() {
        btnSignUp.isEnabled = false
        btnGoogle.isEnabled = false
        btnGithub.isEnabled = false
        btnGoogle.alpha = 0.5f
        btnGithub.alpha = 0.5f
    }

    private fun enableAllButtons() {
        btnSignUp.text = getString(R.string.signup_create_account)
        btnGoogle.isEnabled = true
        btnGithub.isEnabled = true
        btnGoogle.alpha = 1f
        btnGithub.alpha = 1f
        updateVerificationUi()
    }

    private fun isNetworkAvailable(): Boolean {
        val connectivityManager = getSystemService(CONNECTIVITY_SERVICE) as ConnectivityManager
        val activeNetwork = connectivityManager.activeNetwork
        val networkCapabilities = connectivityManager.getNetworkCapabilities(activeNetwork)
        return networkCapabilities != null &&
                (networkCapabilities.hasTransport(NetworkCapabilities.TRANSPORT_WIFI) ||
                        networkCapabilities.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR) ||
                        networkCapabilities.hasTransport(NetworkCapabilities.TRANSPORT_ETHERNET))
    }

    private fun sendPhoneOtp(phone: String) {
        btnSendPhoneOtp.isEnabled = false
        btnSendPhoneOtp.text = getString(R.string.common_sending)
        authManager.startPhoneVerification(
            activity = this,
            rawPhone = phone,
            onCodeSent = { sentVerificationId, token ->
                verificationId = sentVerificationId
                resendToken = token
                lastOtpTargetPhone = phone.trim()
                clearPhoneOtpBlockCounter()
                btnSendPhoneOtp.isEnabled = true
                btnSendPhoneOtp.text = getString(R.string.signup_send_phone_otp)
                btnResendPhoneOtp.isEnabled = true
                setPhoneStatus(false, getString(R.string.signup_phone_otp_sent_status), false)
            },
            onVerified = { result ->
                btnSendPhoneOtp.isEnabled = true
                btnSendPhoneOtp.text = getString(R.string.signup_send_phone_otp)
                handlePhoneVerificationResult(result)
            },
            onError = { message ->
                handlePhoneOtpBlockedErrorIfNeeded(message)
                btnSendPhoneOtp.isEnabled = true
                btnSendPhoneOtp.text = getString(R.string.signup_send_phone_otp)
                Toast.makeText(this, message, Toast.LENGTH_LONG).show()
            }
        )
    }

    private fun handlePhoneVerificationResult(result: AuthResult) {
        when (result) {
            is AuthResult.Success -> {
                clearPhoneOtpBlockCounter()
                phoneVerified = true
                lastOtpTargetPhone = etPhone.text?.toString()?.trim().orEmpty()
                setPhoneStatus(true, getString(R.string.signup_phone_verified), true)
                updateVerificationUi()
            }
            is AuthResult.VerificationRequired -> {
                if (result.phoneVerified) {
                    clearPhoneOtpBlockCounter()
                }
                phoneVerified = result.phoneVerified
                if (result.phoneVerified) {
                    lastOtpTargetPhone = etPhone.text?.toString()?.trim().orEmpty()
                }
                setPhoneStatus(
                    result.phoneVerified,
                    if (result.phoneVerified) getString(R.string.signup_phone_verified) else getString(R.string.signup_phone_not_verified),
                    result.phoneVerified
                )
                updateVerificationUi()
            }
            is AuthResult.Error -> {
                Toast.makeText(this, result.message ?: getString(R.string.signup_phone_verification_failed), Toast.LENGTH_LONG).show()
                setPhoneStatus(false, getString(R.string.signup_phone_not_verified), false)
            }
            AuthResult.Cancelled -> Unit
        }
    }

    private fun updateVerificationUi() {
        val isFullyVerified = emailVerified && phoneVerified

        etEmail.isEnabled = !isFullyVerified
        etPhone.isEnabled = !isFullyVerified

        btnSendEmailOtp.isEnabled = !isFullyVerified
        btnCheckEmailVerified.isEnabled = !isFullyVerified
        btnSendPhoneOtp.isEnabled = emailVerified && !isFullyVerified
        btnResendPhoneOtp.isEnabled = resendToken != null && !phoneVerified && !isFullyVerified
        btnVerifyPhoneOtp.isEnabled = !phoneVerified && !isFullyVerified
        btnEditVerifiedContacts?.visibility = if (isFullyVerified) View.VISIBLE else View.GONE
        tvVerifiedContactsLockedHint?.visibility = if (isFullyVerified) View.VISIBLE else View.GONE
        btnSignUp.isEnabled = isFullyVerified
    }

    private fun resetEmailVerificationState() {
        emailVerified = false
        lastVerifiedEmail = null
        setEmailStatus(false, getString(R.string.signup_email_not_verified), false)
        resetPhoneVerificationState()
    }

    private fun resetPhoneVerificationState() {
        phoneVerified = false
        verificationId = null
        resendToken = null
        lastOtpTargetPhone = null
        etPhoneOtp.text?.clear()
        clearPhoneOtpBlockCounter()
        setPhoneStatus(false, getString(R.string.signup_phone_not_verified), false)
        updateVerificationUi()
    }

    private fun handlePhoneOtpBlockedErrorIfNeeded(message: String) {
        if (isOtpBlockedError(message)) {
            startPhoneOtpBlockCounter()
        }
    }

    private fun isOtpBlockedError(message: String): Boolean {
        val normalized = message.lowercase()
        return normalized.contains("blocked") && normalized.contains("unusual activity")
    }

    private fun startPhoneOtpBlockCounter() {
        phoneOtpBlockTimer?.cancel()
        tvPhoneOtpBlockedCountdown?.visibility = View.VISIBLE

        phoneOtpBlockTimer = object : CountDownTimer(PHONE_OTP_BLOCK_COOLDOWN_MILLIS, 1000L) {
            override fun onTick(millisUntilFinished: Long) {
                val totalSeconds = millisUntilFinished / 1000
                val minutes = totalSeconds / 60
                val seconds = totalSeconds % 60
                tvPhoneOtpBlockedCountdown?.text =
                    getString(R.string.signup_phone_otp_blocked_countdown, minutes, seconds)
            }

            override fun onFinish() {
                tvPhoneOtpBlockedCountdown?.visibility = View.GONE
                tvPhoneOtpBlockedCountdown?.text = ""
                phoneOtpBlockTimer = null
            }
        }.start()
    }

    private fun clearPhoneOtpBlockCounter() {
        phoneOtpBlockTimer?.cancel()
        phoneOtpBlockTimer = null
        tvPhoneOtpBlockedCountdown?.visibility = View.GONE
        tvPhoneOtpBlockedCountdown?.text = ""
    }

    override fun onDestroy() {
        clearPhoneOtpBlockCounter()
        super.onDestroy()
    }

    private fun setEmailStatus(verified: Boolean, text: String, successTone: Boolean) {
        tvEmailVerificationStatus.text = text
        val color = if (verified || successTone) R.color.accent_green else R.color.red
        tvEmailVerificationStatus.setTextColor(ContextCompat.getColor(this, color))
    }

    private fun setPhoneStatus(verified: Boolean, text: String, successTone: Boolean) {
        tvPhoneVerificationStatus.text = text
        val color = if (verified || successTone) R.color.accent_green else R.color.red
        tvPhoneVerificationStatus.setTextColor(ContextCompat.getColor(this, color))
    }

    private fun isValidIndianPhone(phone: String): Boolean {
        return phone.length == 10 && phone.all { it.isDigit() }
    }

    private fun showVerificationRequiredDialog(result: AuthResult.VerificationRequired) {
        val details = buildString {
            append(result.message)
            append("\n\n")
            append("Email: ")
            append(if (result.emailVerified) "Verified" else "Not verified")
            append("\n")
            append("Phone: ")
            append(if (result.phoneVerified) "Verified" else "Not verified")
        }

        val dialog = MaterialAlertDialogBuilder(this)
            .setTitle("Verify your account")
            .setMessage(details)
            .setPositiveButton(
                if (!result.phoneVerified) "Verify phone" else "Go to Sign In"
            ) { _, _ ->
                if (!result.phoneVerified) {
                    val phone = result.phone ?: etPhone.text?.toString()?.trim().orEmpty()
                    if (phone.isBlank()) {
                        Toast.makeText(this, "Phone number is required for OTP verification", Toast.LENGTH_LONG).show()
                    } else {
                        openPhoneVerification(phone)
                    }
                } else {
                    startActivity(Intent(this, SignInActivity::class.java))
                    finish()
                }
            }
            .setNegativeButton("Sign out") { _, _ ->
                authManager.signOut()
            }

        if (!result.emailVerified && auth.currentUser != null) {
            dialog.setNeutralButton("Resend email") { _, _ ->
                authManager.sendEmailVerificationForCurrentUser { resendResult ->
                    when (resendResult) {
                        is AuthResult.Success -> Toast.makeText(
                            this,
                            "Verification email sent",
                            Toast.LENGTH_SHORT
                        ).show()
                        is AuthResult.Error -> Toast.makeText(
                            this,
                            resendResult.message ?: "Failed to send verification email",
                            Toast.LENGTH_LONG
                        ).show()
                        else -> Unit
                    }
                }
            }
        }

        dialog.show()
    }

    private fun openPhoneVerification(phone: String) {
        val intent = Intent(this, PhoneVerificationActivity::class.java)
            .putExtra(PhoneVerificationActivity.EXTRA_PHONE, phone)
            .putExtra(PhoneVerificationActivity.EXTRA_MODE, PhoneVerificationActivity.MODE_LINK)
        startActivity(intent)
    }
}

package com.kartik.aistudyassistant.ui.home

import android.content.Intent
import android.os.Bundle
import android.text.format.DateUtils
import android.view.LayoutInflater
