    private fun enforceVerificationGate() {
        authManager.checkCurrentUserVerification { result ->
            when (result) {
                is AuthResult.Success -> Unit
                is AuthResult.VerificationRequired -> {
                    Toast.makeText(this, result.message, Toast.LENGTH_LONG).show()
